window.__LIBQ=window.__LIBQ||{};window.__LIBQ["tien-nghich"]=window.__LIBQ["tien-nghich"]||{};window.__LIBQ["tien-nghich"]["q17"]=window.__LIBQ["tien-nghich"]["q17"]||{};window.__LIBQ["tien-nghich"]["q17"]["cotTruyen"]=[{"chuong":1725,"tieuDe":"Đại Hồn Môn","tomTat":"Vương Lâm đứng trên Thiên Sơn quan sát Đại Hồn Môn, một trong hai môn phái mạnh nhất Thiên Ngưu Châu, có sơn môn đỏ rực và đại trận hồn phách bao phủ. Dùng thần thức thăm dò, hắn phát hiện bên dưới dãy núi là địa hỏa chủ mạch của toàn châu, chứa ý chí hỏa phẩm chất cao mà hắn cần để bồi bổ chân thân hỏa bổn nguyên đã bão hòa. Hắn tới gần sơn môn, ẩn thành làn khói và kiên nhẫn quan sát mười ngày, ghi nhận cách đại trận dao động theo đệ tử ra vào. Khi có cơ hội, hắn theo sát một đệ tử nhập trận, dùng cấm chế bổn nguyên triệt tiêu và mô phỏng biến hóa để lẻn vào Đại Hồn Môn mà không bị phát hiện. Đang tiến sâu về phía đỉnh núi đỏ, hắn gặp thần thức cao thủ Không Kiếp sơ kỳ quét ra kèm đại trận phong tỏa, buộc phải nhập vào thân thể một nam đệ tử trong nhóm ba người để tránh. Sau khi thần thức tản đi, Vương Lâm ẩn trong cơ thể nam đệ tử và nghe người bên cạnh thúc giục mau đưa Giải Hồn Quả cho các sư tỷ."},{"chuong":1726,"tieuDe":"Tha Hương Gặp Cố Nhân","tomTat":"Vương Lâm ẩn thân theo nhóm đệ tử Đại Hồn Môn tới ngọn núi đỏ rực, sau đó rời khỏi cơ thể nam tử và hóa thành làn khói bám vào y phục Tống Anh. Khi Tống Anh dùng ngọc giản mở tầng sáng phòng hộ, hắn phân tách thần thức nghiên cứu cấm chế bên trong rồi dùng cấm chế bổn nguyên mô phỏng để lặng lẽ xâm nhập. Bên trong Viêm Mạch Phong tràn ngập hỏa bổn nguyên lực, có nhiều động phủ đệ tử và có cao thủ Không Kiếp sơ kỳ bế quan gần địa hỏa mạch, khiến Vương Lâm càng thận trọng. Tống Anh phát Giải Hồn tiên quả tới các động phủ, Vương Lâm bám vào tiên quả để vào động phủ cuối cùng và phát hiện người bên trong là Phàn San Lộ. Hắn dùng thần thức gọi tên nàng, khiến nàng lập tức phóng sương mù phong bế động phủ, rồi hai người vui mừng tái ngộ sau thời gian xa cách. Phàn San Lộ kể từng gặp Vân Dật Phong ở Quy Nhất Tông ba năm trước và vẫn nhớ ân tình Vương Lâm giúp nàng quay về Tiên Cương. Khi Vương Lâm nói muốn tới địa hỏa chủ mạch tu luyện thần thông, Phàn San Lộ đồng ý dùng danh nghĩa bế quan để đưa hắn tới địa hỏa thất, đồng thời nhắc sư tôn nàng bế quan gần đó nhưng trong thời gian ngắn sẽ không dò xét. Vương Lâm cảm tạ rồi hóa thành làn khói ẩn vào ống tay áo Phàn San Lộ, cùng nàng rời động phủ tiến về khu vực gần địa hỏa chủ mạch."},{"chuong":1727,"tieuDe":"Địa Hỏa Chủ Mạch!","tomTat":"Phàn San Lộ đưa Vương Lâm vào động phủ dưới Viêm Mạch Phong, mở thạch thất địa hỏa chủ mạch và dùng thanh âm kỳ dị phá hỏa long chắn cửa. Sư tôn của nàng ở động phủ cao nhất cảm ứng biến hóa, dùng thần thức quét qua nhưng không xâm nhập, còn Phàn San Mộng cũng tỉnh giấc rồi lặng lẽ đả tọa lại. Vương Lâm hiện thân từ ống tay áo Phàn San Lộ, hấp thu nhiệt lực thành hỏa bổn nguyên và tiến thẳng tới vị trí sâu nhất ba mươi bảy trượng để tu luyện. Sau ba ngày, khí tức hắn dung hợp với địa hỏa chủ mạch, hỏa bổn nguyên gần bão hòa, nên hắn bắt đầu cắn nuốt ý chí địa hỏa để ngưng tụ bổn nguyên chân thân. Phàn San Lộ rời thạch thất, còn Vương Lâm tiếp tục lao sâu xuống chủ mạch và sau sáu ngày tìm được đầu long hồn khổng lồ rồi nhảy vào bên trong. Hành động này khiến toàn bộ địa hỏa chủ mạch và Viêm Mạch Phong chấn động dữ dội, buộc sư tôn Phàn San Lộ phát hiện, thuấn di xuống mở tung thạch thất trong sát khí."},{"chuong":1728,"tieuDe":"Thiếu Phụ Tính Sai!","tomTat":"Khi Viêm Loan thuấn di tới thạch thất, Vương Lâm lập tức để bổn tôn mượn ngọn lửa dung nhập vào đại địa, theo địa hỏa chủ mạch thoát đi nhằm kéo sự chú ý khỏi bổn nguyên chân thân. Viêm Loan phát hiện địa hỏa chủ mạch chấn động, nổi sát cơ truy kích và dùng cổ kính đồng xanh phóng hắc khí hóa thành mặt quỷ khổng lồ áp sát Vương Lâm. Biến cố khiến viêm mạch sơn rung chuyển, đệ tử Đại Hồn Môn bay ra quan sát, Phàn San Lộ bị Phàn San Mộng nghi ngờ đưa ngoại nhân vào nhưng lạnh lùng phản bác. Ở sâu trong địa hỏa chủ mạch, bổn nguyên chân thân Vương Lâm cắn nuốt hỏa ý chí của long hồn, khuôn mặt dần hóa thành da thịt chân chính và chỉ còn mái tóc giữ hình lông Chu Tước. Vương Lâm lợi dụng khả năng thuấn di trong địa hỏa chủ mạch để giữ khoảng cách, cố ý dẫn Viêm Loan lệch khỏi nơi chân thân đang ngưng tụ. Tuy nhiên long hồn giãy giụa quá mạnh khiến Viêm Loan nhận ra bổn tôn chỉ là mồi nhử, lập tức bỏ hướng truy đuổi cũ để lao về phía bổn nguyên chân thân."},{"chuong":1729,"tieuDe":"Tỏ Rõ Ý Chí!","tomTat":"Viêm Loan nhận ra bóng người bị lửa bao vây chỉ là kế hoãn binh nên không truy kích, mà tiếp tục tiến sâu vào lòng đất tìm địa hỏa chủ mạch. Vương Lâm cảm ứng được nguy cơ, dùng bổn tôn ra tay ngăn nàng bằng Huyết Kiếm, trường thương bảy màu và Huyền La kim ấn; Viêm Loan nhận ra khí tức Đạo Cổ cùng khí tức Đại Thiên Tôn nhưng vẫn quyết tâm truy tìm. Trong khi đó bổn nguyên chân thân của Vương Lâm trong đầu long hồn gấp rút cắn nuốt, tóc lông Chu Tước dần chuyển đen, báo hiệu quá trình ngưng tụ sắp hoàn thành. Long hồn bất ngờ dồn toàn bộ ý chí, co rút thành quầng sáng cỡ nắm tay rồi lao vào mi tâm chân thân để đoạt xá. Trước ý chí long hồn ập tới như bão tố, Vương Lâm minh ngộ hỏa bổn nguyên của mình không nằm ở Chu Tước mà ở ý chí ánh nến trong gió: nhỏ bé nhưng bất khuất, không cam tắt đi. Bổn nguyên chân thân mở mắt, thần thức của Vương Lâm dùng ý chí nghịch thiên mà tiến để đối kháng long hồn."},{"chuong":1730,"tieuDe":"Tiên Tổ Bát Cực!","tomTat":"Trong địa hỏa chủ mạch, tiếng gầm phản kháng từ bổn nguyên chân thân của Vương Lâm khiến thiếu phụ Đại Hồn Môn lập tức phát hiện và lao tới. Bổn tôn Vương Lâm theo sau nhưng cách biệt tu vi quá lớn, chỉ có thể giữ Định Thân Thuật làm thủ đoạn chờ thời cơ. Thiếu phụ dùng thần thức nhận ra bổn nguyên chân thân của Vương Lâm đang ngưng tụ, kinh hãi vì trước nay nàng chỉ từng thấy lão tổ Đại Hồn Môn có năng lực tương tự, đồng thời hiểu rằng nếu quá trình hoàn tất thì địa hỏa mạch sẽ sụp đổ. Bên trong địa hỏa mạch, bổn nguyên chân thân Vương Lâm bộc phát ý chí, nghiền nát và cắn nuốt toàn bộ ý chí còn sót lại của hỏa long hồn. Tiếng gào thê lương từ sâu trong lòng đất Thiên Ngưu Châu hòa cùng ý chí vừa hấp thu khiến Vương Lâm rơi vào ảo giác giữa tinh không. Trong ảo giác, hắn chứng kiến Thiên Ngưu khổng lồ toàn thân tỏa băng hàn đối đầu với Tiên Tổ mặc hoàng bào, rồi thấy Tiên Tổ thi triển Bát Cực Tiên Đạo, Cực Hỏa Đạo để trấn áp Thiên Ngưu. Cảnh tượng này mở ra manh mối về phong ấn Thiên Ngưu và một thủ đoạn đặc thù của Vương Lâm dù hắn không mang huyết mạch Tiên Tộc."},{"chuong":1731,"tieuDe":"Phân Thân Kinh Khủng!","tomTat":"Vương Lâm sau khi dung hợp thần thức với bổn tôn đã nhớ lại cảnh Tiên Tổ thi triển Cực Hỏa Đạo, rồi tự mình đem thần thông này ra thực chiến. Nhờ sự cộng hưởng giữa bổn tôn, hỏa bổn nguyên chân thân và phân thân trong xác đá ở vùng hư vô, hắn tạo ra vòng thanh khí phá tan ba vạn sáu ngàn mặt quỷ của thiếu phụ Đại Hồn Môn và ép nàng phải liên tiếp dùng huyết nhân cùng chiếc ô màu lam để chống đỡ. Vòng khói thứ hai đánh nứt nặng chiếc ô hộ thân, còn lực va chạm khiến cả hai cùng bị chấn lui và thổ huyết. Qua lần xuất thủ này, Vương Lâm ngộ ra phân thân xác đá có bản chất sinh ra tương tự Tiên Tổ và Cổ Tổ, đồng thời hiểu rằng Cực Hỏa Đạo tiêu hao lực lượng phân thân chứ không trực tiếp bào mòn tu vi bổn tôn. Sau đó hắn gom toàn bộ biển lửa còn sót trong địa hỏa chủ mạch hóa thành hai chưởng ấn lửa khổng lồ đánh tới đối phương rồi dùng Súc Địa Thành Thốn rút khỏi chiến trường. Trở lại đỉnh Thiên Sơn, hắn tự xác nhận hỏa bổn nguyên chân thân đã thành nên thực lực tăng gấp đôi, nhưng đúng lúc chuẩn bị rời đi thì bị một giọng nói già nua bí ẩn của Đại Hồn Môn chặn lại từ phía sau."},{"chuong":1732,"tieuDe":"Bốn Chữ!","tomTat":"Vương Lâm rời địa hỏa mạch, dung nhập thiên địa rồi na di tới Thiên Sơn, nơi Thanh Ngưu chân nhân đã dùng bổn nguyên chân thân ngồi chờ giữa tuyết. Thanh Ngưu yêu cầu hắn hiển hóa bổn nguyên chân thân; Vương Lâm triệu xuất hỏa bổn nguyên chân thân, còn lão giải thích chân thân của mình do hàn bổn nguyên ngưng tụ và xác nhận Vương Lâm là người thứ ba lão từng thấy có năng lực này. Sau đó Thanh Ngưu chiêu mộ Vương Lâm làm trưởng lão Đại Hồn Môn, hứa cấp núi, động phủ, tài nguyên và đạo pháp, đồng thời dùng chuyện không nhắc tới địa hỏa chủ mạch để tạo áp lực vô hình. Lão tiết lộ Đại Hồn Môn có Hồn Diễn Đạo, một đạo thuật tính toán không chỉ suy diễn người khác mà còn thay đổi bản thân để khó bị suy tính. Trước khi hương tuyết cháy hết, Vương Lâm đột ngột rời đi; Thanh Ngưu không ngăn cản mà cho rằng nếu hắn đúng là người tổ tiên từng nói tới thì sẽ quay lại. Vương Lâm lần lượt tới nhiều nơi trên Thiên Ngưu Châu, phát hiện cây cối tự nhiên thành chữ Vương, khe nứt đất gần Thương Long Tông thành chữ Lâm, rồi gặp cây cầu đá cổ có bia ghi Cầu Quy Lai. Ba phát hiện ghép thành bốn chữ Vương Lâm quy lai, khiến hắn chấn động mạnh."},{"chuong":1733,"tieuDe":"Trưởng Lão Đại Hồn Môn!","tomTat":"Vương Lâm nhìn thấy bốn chữ Vương Lâm quy lai trên bia đá bên cầu hồng và hiểu rằng có người đã tính toán vượt năm tháng để chờ hắn tới Đại Hồn Môn. Hắn quyết định không phá thế cục mà trở thành trưởng lão tông môn, mượn nơi này để tìm hiểu thêm về Tiên Cương đại lục. Trở lại Thiên Sơn, hắn được Thanh Ngưu chân nhân vui mừng trao ngọc giản màu tím chứa công pháp truyền thừa Hồn Diễn Đạo rồi dẫn về Đại Hồn Môn. Chương cũng mở rộng quy mô Đại Hồn Môn với ba trăm sáu mươi chủ phong, mười vạn đệ tử và nhiều đạo pháp thu được từ các tông phái đã bị hủy diệt. Khi về tới tông môn, Viêm Loan dẫn đệ tử Viêm Mạch Phong ra chặn đường, công khai chuyện Vương Lâm hủy núi để ép Thanh Ngưu chân nhân và các trưởng lão phải đối mặt. Vương Lâm cười lớn lập uy, thi triển Thần Chấn khiến thiên không xoáy vặn, phượng hoàng hư ảnh của Viêm Loan sắp sụp đổ và khí tức Đạo Cổ bị lộ trước nhiều trưởng lão. Thanh Ngưu chân nhân lập tức che giấu khí tức ấy khỏi ngoại giới, còn Vương Lâm tiếp tục tung Yêu thuật — Phong hỏa thành sơn."},{"chuong":1734,"tieuDe":"Thiên Ngưu Tử Hồn!","tomTat":"Vương Lâm phá tan hư ảnh phượng hoàng bảo vệ Viêm Loan, triển khai tám trụ khói gió lửa bao phủ nàng trong cơn lốc. Viêm Loan rơi vào nguy hiểm, cắn lưỡi phun máu thi triển Hồn Huyễn Thuật triệu hồi thân ảnh đệ cửu Tiên Tổ — vị Tiên Tổ từng phong ấn mười triệu đạo hồn, tu vi đỉnh phong nhưng từng khiêu chiến Đạo Nhất thiên tôn thất bại bị giết. Vương Lâm lui ba bước, hư ảnh Đạo Cổ mặc giáp cổ xưa hiện ra sau lưng, hắn thi triển Sanh Tử Nghịch Động biến sinh cơ trong thân Viêm Loan thành tử khí, đồng thời dẫn động tử khí khổng lồ từ nơi Thiên Ngưu bị phong ấn dưới lòng đất. Tử khí dung hợp hóa hình hài Thiên Ngưu khổng lồ gào thét trên bầu trời, chấn động toàn Đại Hồn Môn, kể cả các lão quái ẩn tu cũng phải bay ra. Bổn tôn Thanh Ngưu chân nhân trên ngọn núi cao nhất mở mắt, kích động nhận ra Vương Lâm chính là người mà tổ tiên đã tiên đoán — vô số năm trước tổ tiên di chuyển tông môn tới Thiên Ngưu Châu chọn địa hỏa chủ mạch để đợi người có thể dẫn động Thiên Ngưu. Thanh Ngưu chân nhân tuyên bố sẽ bồi thường Viêm Mạch Phong cho Viêm Loan."},{"chuong":1735,"tieuDe":"Khắc Chết Hắn Đi!","tomTat":"Thanh Ngưu chân nhân hiện thân giữa cuộc đối đầu của Vương Lâm và Viêm Loan, dùng thần thức phá tan chín tầng Cổ đạo vô tiên của Vương Lâm, đẩy Viêm Loan lui trăm trượng và khiến chư trưởng lão Đại Hồn Môn cúi đầu tham kiến. Ông công khai tuyên bố Vương Lâm là trưởng lão do mình mời về, ra lệnh giữ bí mật mọi chuyện liên quan đến hắn, đồng thời hứa bù động phủ mới và cho Viêm Loan vào Tàng Hồn Các ba ngày. Vương Lâm được trao ngọc giản thông hành cấm chế, được hứa ba phần lễ vật tổ tiên Đại Hồn Môn và một lần vào Tàng Hồn Các, nhưng lại chủ động chọn Viêm Mạch Phong đã tàn phá làm động phủ. Trước khi đi, hắn chỉ Phàn San Mộng, nói động phủ thiếu nữ tỳ và muốn Viêm Loan tặng nàng cho mình, khiến Viêm Loan nổi giận. Vương Lâm dùng hỏa bổn nguyên chân thân dung nhập Viêm Mạch Phong, đốt sạch cấm chế cũ, bổ sung hỏa lực và ý chí, khiến ngọn núi đỏ rực hơn trước với lửa cháy vĩnh hằng. Sau đó Viêm Loan triệu Phàn San Mộng, mắng nàng từng khắc chết Thất Thải Tiên Tôn và khiến Liên Đạo Phi mất tích, rồi ép nàng dùng mị công cùng sắc đẹp tiếp cận Vương Lâm để khắc chết hắn. Phàn San Mộng cầu xin không được, bị cuồng phong cuốn ra ngoài, cuối cùng thu lại oán độc, đổi sang vẻ mị hoặc và bước tới ngọn núi của Vương Lâm."},{"chuong":1736,"tieuDe":"Hồn Diễn Đạo Lôi!","tomTat":"Vương Lâm ẩn tu trong động phủ vốn thuộc về Viêm Loan tại Viêm Mạch Phong của Đại Hồn Môn, nơi bổn nguyên chân thân hắn đã dung nhập vào ngọn núi. Hắn lấy ngọc giản màu tím chứa Hồn Diễn Đạo ra nghiên cứu, nhận ra đạo thuật này nhập môn dễ nhưng đại thành cần thời gian gần như không thể đạt, vì vậy hiểu vì sao Thanh Ngưu lão tổ dễ dàng trao cho mình. Trong lúc đó Phàn San Mộng tới ngoài Viêm Mạch Phong cầu kiến theo lệnh sư tôn, mang lễ vật nhưng bị Vương Lâm bỏ mặc suốt ba ngày. Sau ba ngày, Vương Lâm đạt tiểu thành Hồn Diễn Đạo, ngưng tụ hồn nhân do mười vạn minh tự tạo thành và dùng nó suy diễn may rủi bản thân. Hồn nhân bái lạy bốn lần, khiến hắn nhìn thấy cảnh tương lai bản thân bị trấn áp dưới lôi sơn, phía trên là chiến xa lôi đình cùng một thân ảnh quen thuộc làm hắn chấn động không thể tin. Vương Lâm thu hồn nhân về nuôi dưỡng, dự định sau này dùng Hồn Diễn Đạo tìm Tư Đồ Nam, Thanh Thủy và Lý Thiến Mai. Khi rời động phủ, hắn lướt qua Phàn San Mộng đang suy yếu và phẫn nộ, rồi theo bản đồ trong ngọc giản phá cấm của Thanh Ngưu lão tổ bay vào sâu Đại Hồn Môn tìm Thanh Thiên Phong."},{"chuong":1737,"tieuDe":"Tàn Hồn!","tomTat":"Vương Lâm đi thẳng qua tầng tầng cấm chế của Đại Hồn Môn tới Thanh Thiên Phong, cấm địa bế quan của Thanh Ngưu lão tổ, và nhận ra ngọn núi này do một kiện chí bảo biến thành. Trên đỉnh núi, hắn đối diện Thanh Ngưu chân nhân và thẳng thắn nghi ngờ lời đồn về Hồn Diễn Đạo, cho rằng không ai có thể bế quan mười bảy vạn tám ngàn năm chỉ để tu một thần thông mà vẫn giữ được sinh cơ. Thanh Ngưu chân nhân không tranh biện, trao cho hắn ba hộp gấm do lão tổ đời đầu Đại Hồn Môn chuẩn bị rồi mở khe không gian dẫn tới Tàng Hồn Các. Tàng Hồn Các là thánh địa chín tầng lưu giữ công pháp thần thông bằng hồn thể, có quy củ mỗi người chỉ được chọn một lần nếu không lập thêm công lao môn phái. Vương Lâm dùng ngọc giản vượt qua tượng đá canh cửa, đi qua tầng một tới tầng năm và thấy các hồn thể ngày càng ít nhưng khí tức càng mạnh, song vẫn chưa tìm được Trọng Huyễn Thuật hay thuật triệu hồi hồn phách Tiên Tổ. Khi hắn bước lên cầu thang tầng sáu, lực cản khiến thân thể chấn động; trong tầng sáu, Viêm Loan đang tu luyện và nhận ra người tới có khả năng là Vương Lâm, đồng thời muốn xem hắn có thể lên tầng sáu hay không để phán đoán tu vi thật."},{"chuong":1738,"tieuDe":"Đánh Cuộc!","tomTat":"Khi Vương Lâm bước lên cầu thang tầng sáu Tàng Hồn Các, Thanh Ngưu chân nhân ở Thanh Thiên Phong mở mắt quan sát và nhận định tầng sáu gần như là cực hạn hiện tại của hắn. Vương Lâm vượt qua vô số ảo thuật, dùng Cổ Thần tinh điểm và yêu ma tinh điểm chống áp lực, rồi nhận ra bậc cuối cùng không thể dẫm lên mà phải bỏ qua để vào tầng sáu. Thanh Ngưu chân nhân khen hắn lần đầu đã tự phá được huyền cơ, đồng thời nhắc lão tổ đời đầu từng tính toán Vương Lâm ba trăm năm sau mới vào được tầng chín. Trong tầng sáu, Vương Lâm gặp Viêm Loan, quét qua hơn sáu mươi hồn thể công pháp cấp Không Kiếp và phát hiện Đa Trọng Huyễn Thuật cùng Dẫn Hồn thuật đều chưa đầy đủ. Viêm Loan cho biết bản đầy đủ ở tầng bảy trở lên, khinh thường rằng Vương Lâm không đủ tư cách. Vương Lâm cho rằng tầng bảy cần tu vi ngang Không Kiếp trung kỳ nhưng vẫn đề nghị đánh cuộc; Viêm Loan tin hắn không thể vượt qua nên lấy chiếc ô màu lam ra làm vật cược và hỏi hắn sẽ đặt cược thứ gì."},{"chuong":1739,"tieuDe":"Muốn Đạp Bước Tận Trời Xanh","tomTat":"Vương Lâm lấy Huyết Kiếm ra làm tiền cược với Viêm Loan, buộc nàng đem cây ô lam phòng ngự kinh người đặt ngang hàng trong ván cược hắn có thể bước vào tầng thứ bảy Tàng Hồn Các. Khi hắn đặt chân lên cầu thang cổ kính mười chín bậc, dị tượng lập tức phủ khắp Đại Hồn Môn, bậc thang hư ảo hiện lên giữa trời đêm khiến vô số tu sĩ và cả các lão quái bế quan đều thức tỉnh quan sát. Thanh Ngưu lão tổ cũng chú ý đến việc này, cho rằng Vương Lâm quá liều lĩnh và rất có thể sẽ bị cấm chế tầng bảy làm nhụt nhuệ khí. Vương Lâm vượt qua năm bậc đầu, nhưng tại bậc thứ năm, thần thức cấm chế khổng lồ bùng nổ trong tâm thần hắn, hóa thành tiếng quát ép lui đầy uy áp. Hắn liền triệu hồi bổn nguyên chân thân từ Viêm Mạch Phong, khiến biển lửa ngập trời dung nhập vào thân thể, rồi một mạch bước lên tới bậc thứ mười ba trước sự chấn động của toàn môn và vẻ không thể tin nổi của Viêm Loan. Thanh Ngưu lão tổ nhận ra bổn nguyên chân thân của Vương Lâm đã gần chạm tới trình độ chân tiên, nhưng vẫn phán đoán bậc mười sáu sẽ là cực hạn của hắn. Đúng lúc mọi người thấy Vương Lâm lộ vẻ hoảng hốt và tưởng hắn sắp thất bại, ánh sáng quanh hắn bùng lên, hắn xóa sạch dao động trong mắt và tuyên bố Viêm Loan đã mừng quá sớm, bởi cây ô kia hắn nhất định muốn lấy."},{"chuong":1740,"tieuDe":"Lại Đánh Cuộc Một Lần!","tomTat":"Vương Lâm vượt các bậc thang cuối vào tầng bảy Tàng Hồn Các bằng cách lần lượt bộc phát nhiều loại bổn nguyên, đồng thời tuyên bố ý chí không chịu phục tùng mà muốn nắm số phận trong tay. Cả Đại Hồn Môn chấn động vì từ nay tầng bảy không còn là nơi chỉ năm lão tổ từng bước vào; Thanh Ngưu chân nhân ở Thanh Thiên Phong bất an vì tiên đoán của tổ tiên đã sai lệch. Sau khi thắng cược cũ, Vương Lâm thu hồi Huyết Kiếm và đoạt chiếc ô màu lam của Viêm Loan, khiến nàng phải đưa ra cược mới rằng hắn không thể vào tầng tám. Viêm Loan lấy hồ lô màu tím của La Vân Hải làm vật cược, hé lộ pháp bảo này còn ba ngàn vạn đạo hồn, chỉ có một lần thi triển nhưng đạt uy lực Không Kiếp trung kỳ tối cường và có thể phối hợp Hồn Diễn Quy Đạo Thuật gọi đệ cửu Tiên Tổ giáng xuống. Vương Lâm tìm được Trọng Huyễn Thuật cùng Hồn Diễn Quy Đạo Thuật tương đối đầy đủ ở tầng bảy, cảm ứng phân thân đang trưởng thành nhanh hơn dự đoán rồi nhận cược. Hắn đặt chân lên cầu thang tầng tám, khiến hư ảnh cầu thang trên trời Đại Hồn Môn càng khổng lồ, còn Viêm Loan vì không nhìn được tầng bảy nên dùng thần thức đè nén linh hồn một đệ tử để mượn làm đôi mắt theo dõi."},{"chuong":1741,"tieuDe":"Phân Thân Trấn Áp!","tomTat":"Cầu thang khổng lồ của Tàng Hồn Các huyễn hóa thông lên trời, Vương Lâm đứng dưới bậc thang với hư ảnh và khí thế khiến toàn Đại Hồn Môn chấn động. Ánh mắt hắn quét qua khiến đệ tử, trưởng lão và cả lão quái bế quan đều cảm thấy Nguyên Thần như sắp rời thân; thần thức Viêm Loan trong nữ đệ tử suýt bị đánh bật, còn Thanh Ngưu chân nhân phải lao khỏi động phủ, hóa lộ bổn nguyên chân thân và kinh nghi thân phận của hắn. Vương Lâm nhắm mắt bước lên, liên tục qua mười lăm bậc, mở mắt ở bậc mười tám rồi tuyên bố mình đã thắng Viêm Loan trước khi đặt chân lên bậc mười chín, tiến vào tầng tám Tàng Hồn Các. Toàn Đại Hồn Môn xôn xao vì Vương trưởng lão liên tiếp xông lên hai tầng, trong khi Thanh Ngưu chân nhân càng thêm phức tạp vì không nhận ra khí tức giống Cổ Tổ trên hư ảnh ấy. Ở tầng sáu, Viêm Loan thua cược nhưng giữ chặt hồ lô định lật lọng; Vương Lâm từ tầng tám quay xuống, dùng khí thế phân thân lần đầu được điều động hoàn toàn để trấn áp tâm thần nàng. Viêm Loan bị ép đến mức sinh sợ hãi, buông tay để hồ lô bay vào tay Vương Lâm, đồng thời trong đạo tâm bị lưu lại một khe hở khiến về sau khó dám đối đầu hắn. Sau khi thu được vật cược, Vương Lâm trở lại tầng tám, nơi phủ đầy tro bụi và có chín hồn thể tỏa sáng, mỗi hồn thể chứa một thần thông cực mạnh của Đại Hồn Môn."},{"chuong":1742,"tieuDe":"Hồn Diễn Đạo!","tomTat":"Trong tầng tám Tàng Hồn Các, Vương Lâm thu lại khí thế mượn từ phân thân và cân nhắc việc lên tầng chín, nhưng uy áp trên cầu thang quá mạnh nên hắn tạm bỏ ý định, chỉ ghi nhớ rằng cửu trọng ảo thuật ngày sau bắt buộc phải lấy. Hắn quan sát chín hồn thể, nhận ra Đa Trọng Huyễn Thuật ở hồn thể thứ ba chỉ tới bát trọng, còn Hồn Diễn Quy Đạo Thuật ở hồn thể thứ bảy lại cực kỳ đầy đủ, nên chọn hấp thu thuật này. Sau ba ngày thổ nạp, khẩu quyết dung nhập linh hồn hắn như bản năng, ánh mắt sinh thêm sương mù mộng ảo, đồng thời hắn hiểu cơ chế các thuật này đều cần phân hóa tàn hồn câu thông thiên địa. Khi Vương Lâm rời Tàng Hồn Các, Thanh Ngưu lão tổ thở phào và nhớ tới tiên cơ của lão tổ đời đầu: sau khi Vương Lâm vào tầng chín, Tam đại tông phái Lục Ma Châu sẽ liên thủ diệt Đại Hồn Môn và Quy Nhất Tông để cướp Thiên Ngưu bị trấn áp dưới Thiên Ngưu Châu. Thanh Ngưu cũng nhắc nguồn gốc Hồn Diễn Đạo, Đạo Diễn Hồn từ một môn phái ẩn trên Tiên Cương đại lục và lời đồn Đạo Diễn Thuật của Huyền Đạo nhất mạch Trung Châu khiến lòng bất an. Vương Lâm trở về ngọn núi cháy, sai Phàn San Mộng quét dọn động phủ, quyết ở lại Đại Hồn Môn nâng cao tu vi trước khi đi tìm sư tôn vì cảm thấy Đạo Cổ nhất mạch là kiếp nạn tương lai. Cuối chương, hắn lấy ra ba hộp gấm lễ vật Thanh Ngưu lão tổ tặng và nhìn vào một hộp để xem bên trong là gì."},{"chuong":1743,"tieuDe":"Ba Phần Lễ Vật","tomTat":"Vương Lâm mở hộp gấm thứ nhất và nhận Không Gian Thạch, một dị bảo có vô số không gian độc lập, có thể mở Không Gian trữ vật một lần giữa pháp tắc Tiên Cương và còn có thể nuôi dưỡng Thiên Đạo không hoàn chỉnh. Hộp thứ hai chứa ngọc giản Hồn Diễn đạo bằng sương mù, do Hồn Diễn đạo suốt đời của giọng nói già nua biến thành, có thể thi triển một lần Tiên Cương biến hóa để suy tính việc trọng yếu. Hộp thứ ba để lộ giọt thủy bổn nguyên cực đậm, luyện từ chín mươi chín dòng sông Thiên Hà châu và thủy bổn nguyên của nhiều tu sĩ, đúng là vật Vương Lâm đang cần để phá thế đình trệ Không Linh hậu kỳ. Từ đó hắn tự minh định lộ trình tu luyện: bảy bổn nguyên hiện có, thủy bổn nguyên đại thành sẽ thành tám đạo, đủ chín đạo sẽ bước vào Không Huyền. Giọng nói già nua gửi gắm Vương Lâm che chở Đại Hồn Môn một lần để hậu nhân trở lại Trung Châu; Vương Lâm kiểm tra không thấy âm mưu rồi thề trước trời nếu có năng lực sẽ làm, khiến sấm sét vang động cả tông môn. Thanh Ngưu lão tổ trên Thanh Thiên Phong chấn động thốt tới lão tổ đời thứ nhất, còn Vương Lâm triệu hỏa bổn nguyên chân thân làm hộ pháp, đề phòng Phàn San Mộng và bắt đầu bế quan với Không Gian Thạch trong tay."},{"chuong":1744,"tieuDe":"Bổn Nguyên Thứ Tám!","tomTat":"Vương Lâm biết mình chỉ có một cơ hội mở Không Gian trữ vật không tổn hao nhờ Không Gian Thạch, nên chọn lấy Dĩ Ti khôi lỗi ra làm hộ pháp trong động phủ. Hắn bố trí thêm bổn nguyên chân thân canh ngoài động và xem ấn ký Văn Thú trên tay là phòng tuyến cuối, rồi bắt đầu dung hợp giọt thủy bổn nguyên. Quá trình dung hợp diễn ra theo từng vòng ngưng–tán: khi ngưng, thân thể hắn bị hút cạn nước và máu thành thây khô; khi tán, thân thể lại hồi phục, mỗi vòng kéo dài nhiều ngày. Sau mấy tháng, Vương Lâm hoàn thành tám vòng tuần hoàn, nhưng đến vòng thứ chín thì giọt thủy bổn nguyên tiêu tán giữa chừng, khiến hắn thiếu một lần cuối và cần lượng nước lớn để viên mãn. Trong lúc đó, Phàn San Mộng lén tới gần động phủ để tìm cách hoàn thành lệnh sư tôn là từ từ khắc chết Vương Lâm, nhưng bị bổn nguyên chân thân phát hiện và bị Dĩ Ti lao ra truy kích. Động tĩnh khiến môn nhân Đại Hồn Môn chú ý, Viêm Loan cũng nhớ ra việc từng phái Phàn San Mộng và lập tức chạy tới. Vương Lâm nghe biến liền gọi Dĩ Ti trở lại, tự bước ra khỏi động phủ trong hình dạng khô héo như hài cốt, khiến Viêm Loan nhìn thấy mà thét lên kinh hãi."},{"chuong":1745,"tieuDe":"Cực Thiên Thảo Nguyên","tomTat":"Vương Lâm xuất quan trong trạng thái thân thể khô héo như xác chết, khiến Viêm Loan và Phàn San Mộng kinh hãi, nhưng Nguyên Thần của hắn vẫn mạnh mẽ. Hắn hỏi Viêm Loan nơi nào ở Thiên Ngưu Châu có biển rộng hoặc nhiều nước, khiến nàng nhận ra hắn đang hấp thu thủy bổn nguyên chứ không phải luyện công pháp quỷ dị. Viêm Loan ghi lộ tuyến tới vùng biển giao giới Thiên Ngưu Châu và Lục Ma Châu vào ngọc giản giao cho hắn, còn Vương Lâm lập tức rời Đại Hồn Môn để giải quyết tai họa ngầm trong thân thể. Sau một lần thi triển súc địa thành thốn, hắn tới Cực Thiên thảo nguyên, triệu Văn Vương từ ấn ký thủy mặc trên cổ tay và cưỡi nó vượt qua thảo nguyên. Nhiều tán tu dưới đất dùng thần thức dò xét rồi rút lui, nhưng ba người vẫn bám theo nhiều ngày và ra tay đòi cướp mãnh thú phi hành. Vương Lâm dùng Tê Thiên xé nát bàn tay đen khổng lồ của đối phương, khiến ba tán tu kinh hãi bỏ chạy. Hắn thả Dĩ Ti giết một người, sai Văn Vương hút một tu sĩ Không Linh hậu kỳ, còn tự mình dùng bổn nguyên chân thân biển lửa truy sát người thứ ba. Khi kẻ thứ ba sắp bị nuốt chửng, hắn cầu cứu sư tôn, mặt đất Cực Thiên thảo nguyên chấn động và một giọng nói trầm trầm quát Vương Lâm dừng tay."},{"chuong":1746,"tieuDe":"Kinh Biến!","tomTat":"Sau tiếng dừng tay trên Cực Thiên thảo nguyên, Vương Lâm đánh tan nắm tay bùn đất, để bổn nguyên chân thân thiêu chết một kẻ phục kích và dùng địa khí hút sinh cơ thảo nguyên để truy sát tu sĩ thổ độn. Tả Trâu, một tán tu Không Kiếp sơ kỳ, ra mặt đánh bật kẻ bỏ chạy khỏi lòng đất rồi xin Vương Lâm thu đạo pháp vì nơi đây là căn cơ của tán tu Cực Thiên thảo nguyên. Vương Lâm nhận ra vùng thấp nhất, gần địa tâm nhất của Thiên Ngưu Châu có điều cổ quái, thu Dĩ Ti khôi lỗi và Văn Thú rồi rời đi bằng súc địa thành thốn. Sau khi hắn rời đi, Tả Trâu cùng hơn mười tán tu đánh giá Vương Lâm sát phạt quyết đoán, thân thể, khôi lỗi và mãnh thú đều đáng sợ, còn bốn thầy trò Hắc Sơn là tự chuốc họa. Vương Lâm tiếp tục đi về phía Đông theo bản đồ Viêm Loan, dựa vào ký ức Khang Nhân biết Lục Ma Châu là vùng khiến tu sĩ e sợ. Mười ngày sau, hắn tới Đan Hải, vùng biển nội lục giữa Thiên Ngưu Châu và Lục Ma Châu, rồi lặn xuống đáy biển để ngưng tụ phần Thủy bổn nguyên còn thiếu. Khi toàn bộ Đan Hải nổi sóng dữ vì hắn hấp thu bổn nguyên, Vương Lâm phát hiện nơi này bị cấm chế vô hình phong tỏa, chỉ cho vào không cho ra. Bên trong Đan Hải, số lượng lớn tu sĩ lục bào có quỷ hỏa đang điên cuồng giết hại tán tu Thiên Ngưu Châu, mở ra một sát kiếp quy mô lớn."},{"chuong":1747,"tieuDe":"Tu Sĩ Lục Ma!","tomTat":"Lục Ma Châu mở cuộc đồ sát trong Đan Hải, phá động phủ và truy sát tu sĩ Thiên Ngưu Châu giữa vùng biển đã bị phong ấn. Gần phía Lục Ma Châu, ba đại kỳ cắm trong biển làm trung tâm chỉ huy cho mấy ngàn tu sĩ và ba tu sĩ áo trắng, trong đó nữ tử áo trắng dùng la bàn theo dõi toàn chiến trường. Ba người tiết lộ kế hoạch không chỉ giết sạch tu sĩ Thiên Ngưu Châu mà còn luyện hóa Đan Hải thành nửa hạt tiên đan để phá phòng tuyến Thiên Ngưu Châu. Nữ tử áo trắng lấy Tịnh Hóa Ô Dịch của Độc Ma Tông ra, đồng thời điều động Lục Ma vệ thông qua trận pháp để thuấn di truy sát các điểm trắng trên la bàn. Vương Lâm ẩn dưới biển, dung hợp với nước biển để hấp thu và ngưng luyện thủy bổn nguyên, khiến mực nước Đan Hải liên tục hạ xuống mà phe Lục Ma Châu chưa tìm ra nguyên nhân. Khi các mục tiêu Huyền Kiếp còn lại tụ lại chạy về phía Thiên Ngưu Châu, nữ tử áo trắng yêu cầu Tiền sư huynh và thanh niên mặt trắng ra tay. Ở nơi khác dưới đáy biển, Bạch Hổ đang mang Chu Tước và một đồng bạn trọng thương chạy trốn sau kiếp nạn ở Đan Hải, dù hai người bị thương khuyên hắn nên tự rời đi."},{"chuong":1748,"tieuDe":"Đột Phá!","tomTat":"Ba chiến tướng Chu Tước, Bạch Hổ và Huyền Vũ từng rời động phủ giới tới Tiên Cương đại lục, sau khi Thất Đạo Tông không còn thì ẩn cư ở Đan Hải, nhưng nay bị thanh niên mặt trắng và tu sĩ họ Tiền truy sát. Chu Tước và Huyền Vũ trọng thương, Bạch Hổ vẫn mang theo hai đồng bạn bỏ chạy, không chịu tự mình thoát thân. Ở hải vực Lục Ma Châu, nữ tử dưới ba cây đại kỳ phát hiện mực nước Đan Hải giảm bất thường và quyết định sớm dùng Vạn Tịnh Hóa Ô Dịch để thanh tẩy người còn sót lại. Chất lỏng đen khiến nửa vùng biển hóa mực, ăn mòn thân thể và nguyên thần tu sĩ Thiên Ngưu Châu, trong khi tu sĩ lục y không bị thương tổn. Vương Lâm đang bế tắc trong việc ngưng tụ thủy bổn nguyên thì cảm nhận khí tức thủy bổn nguyên từ vùng nước đen, lập tức dịch chuyển tới đó và hấp thu điên cuồng. Nữ tử qua la bàn phát hiện vùng nước đen tiêu tán cùng một điểm trắng dị thường, liền điều năm mươi tổ Lục Ma vệ đi vây giết. Nhờ hấp thu nước biển đen, Vương Lâm hoàn thành lần tuần hoàn thứ chín, ngưng tụ đạo bổn nguyên thứ tám là thủy bổn nguyên, đột phá tới Không Linh hậu kỳ rồi tăng lên Không Linh đỉnh phong. Cuối chương, hắn xác nhận thủy bổn nguyên đã hòa vào huyết dịch, khiến máu của mình trở thành thủy bổn nguyên trong ngũ hành."},{"chuong":1749,"tieuDe":"Gặp Lại Cố Nhân!","tomTat":"Vương Lâm khiến thủy bổn nguyên đại thành trong Đan Hải, ngưng tụ Vạn Tịnh Hóa Ô Dịch rồi dùng hắc thủy tiêu diệt nhiều hư ảnh tu sĩ. Nữ tử cầm la bàn dưới ba cây đại kỳ phát hiện các điểm sáng quanh hắn tắt đi, lập tức dùng la bàn truyền lệnh cho toàn bộ Lục Ma vệ truy sát người đoạt Vạn Tịnh Hóa Ô Dịch. Trên đường đi, Vương Lâm dùng Hồn Diễn Đạo suy tính tương lai nhưng bị một lực lượng u minh chặt đứt, đồng thời nhận ra cấm chế Đan Hải đang ngăn cản mọi biến hóa và có thể bị luyện hóa. Khi hơn mười tu sĩ mặc lục y ẩn nấp truy sát, hắn dùng Hư Hỏa dẫn động sát khí của họ, khiến lửa đen bùng lên và thiêu chết toàn bộ. Sau đó hắn đổi hướng vì phát hiện Bạch Hổ, Chu Tước, Huyền Vũ đang bị thanh niên mặt trắng và tu sĩ họ Tiền của Vô Cực Tông truy đuổi. Ba chiến tướng Thất Đạo Tông dù trọng thương vẫn từ chối gia nhập Vô Cực Tông, nhắc tới một người trong tông sẽ rạng danh Tiên Cương. Khi hai kẻ truy sát áp sát và châm chọc, giọng Vương Lâm lạnh lùng vang lên, cắt ngang cục diện."},{"chuong":1750,"tieuDe":"Thiên Tài Đông Châu Vân Không!","tomTat":"Vương Lâm từ dòng chảy ngầm dưới Đan Hải hiện thân trước nhóm Bạch Hổ, Chu Tước và Huyền Vũ, trực tiếp đối đầu hai tu sĩ Lục Ma Châu đang uy hiếp họ. Tu sĩ họ Tiền khinh địch lao tới thì bị Dĩ Ti khôi lỗi hủy thân thể, hút sạch máu huyết, chỉ còn Nguyên Thần bị Vương Lâm sưu thần rồi phong ấn. Thanh niên mặt trắng nhờ công pháp mẫn cảm máu tanh nhận ra sát khí và oan hồn quanh Vương Lâm, dùng cây quạt vạn mã bôn đằng thoát khỏi bàn tay hư ảo rồi trốn về chỗ nữ tử cầm la bàn. Tại khu vực ba đại kỳ ngoài khơi Lục Ma Châu, nữ tử này hé lộ ba lão tổ đã phái Vân Không tới, dự định luyện hóa Đan Hải thành nửa hạt tiên đan để phá màn chắn Thiên Ngưu Châu và cho đại quân liên minh tam tông xuất động. Chương giới thiệu Vân Không là một trong tứ đại thiên tài Đông Châu, đại sư huynh của toàn bộ đệ tử tam đại tông môn Lục Ma Châu, từng bái dưới môn hạ Võ Phong Đại Thiên Tôn. Sau khi áp chế Dĩ Ti khôi lỗi đang nổi hung, Vương Lâm cùng ba chiến tướng phân tích rằng Lục Ma Châu đã tàn sát phần lớn tu sĩ Thiên Ngưu Châu trong Đan Hải và che giấu thiên địa biến, nên cần rời đi truyền tin cho Đại Hồn Môn, Quy Nhất Tông. Trên đường rời khỏi dòng chảy ngầm, Vương Lâm dùng Hư Hỏa giết các tu sĩ Lục Ma Châu gặp đường nhưng càng đi càng thấy vắng địch bất thường. Cuối chương, hắn trồi lên mặt biển tối đen không trăng, bảo ba người hộ pháp và chuẩn bị thử lực phong ấn của trận pháp Đan Hải."},{"chuong":1751,"tieuDe":"Lần Đầu Gặp Mặt!","tomTat":"Tại Đan Hải, Vương Lâm cẩn thận để lại một tia thần thức hòa vào nước biển làm hậu thủ rồi dùng cấm chế bổn nguyên quan sát đại trận bảy tầng sương mù cùng la bàn hư ảo phía trên. Hắn nhận ra cấm chế này có giá trị cho bổn nguyên của mình nhưng trước tiên phải phá vòng vây, bèn triệu hư ảnh hai đồng tử và dùng tơ huyết sắc mở lối qua năm tầng đầu. Bạch Hổ, Chu Tước và Huyền Vũ hộ pháp cho hắn trong lúc tu sĩ Lục Ma Châu vẫn chưa xuất hiện, khiến tình thế càng thêm căng thẳng. Khi nhóm vừa có đường thoát, một kiếm ảnh kinh khủng từ đáy biển chém lên, phân đôi mặt biển và phá nát nhiều tầng cấm chế, làm Chu Tước cùng Huyền Vũ vốn bị thương phải phun máu. Vương Lâm phản ứng cực nhanh, cuốn ba người lao vào các lỗ hổng cấm chế và tiếp tục vượt qua tầng thứ sáu. Kiếm ảnh sau đó hóa thành thanh y tu sĩ Vân Không, thực chất chỉ là kiếm ý phân thân có sáu thành kiếm ý của bổn tôn. Vân Không cầm trường kiếm bảy thước, lên tiếng ngăn Vương Lâm rời đi, chém sụp tầng sương mù thứ năm rồi lạnh lùng đối mặt với hắn."},{"chuong":1752,"tieuDe":"Hồi Mã Thương!","tomTat":"Vương Lâm mang ba người Bạch Hổ lao qua tầng sáu cấm chế Đan Hải, dùng cấm chế bổn nguyên dung hợp đại trận để vượt vào tầng bảy trong lúc Vân Không truy sát. Vân Không dùng kiếm khí đánh tan tầng sáu và ngưng thành kiếm ảnh ngập trời, buộc Vương Lâm xoay người phản kích bằng ba chưởng ấn từ bổn tôn, hỏa bổn nguyên chân thân và thủy bổn nguyên đại hải. Thủy hỏa bổn nguyên dung hợp diễn biến ra khí bổn nguyên, khiến kiếm khí Vân Không lần đầu hoàn toàn tan nát và tạo cơ hội cho Vương Lâm lùi vào sương mù tầng bảy. Vương Lâm tiếp tục thả Dĩ Ti khôi lỗi phục kích; khôi lỗi bị chém đứt tay phải nhưng cánh tay hóa năm luồng hắc khí chứa lực lượng Đạo Cổ nhập vào Vân Không, khiến hắn bị thương khó thanh trừ. Vương Lâm thu hồi khôi lỗi, đưa ba người Bạch Hổ thoát khỏi đại trận, trong khi Đan Hải được xác nhận không còn tu sĩ Thiên Ngưu Châu sống sót và gần như rơi vào tay Lục Ma Châu. Bên ngoài Đan Hải, hắn dùng Truyền Âm Phù báo tin Đại Hồn Môn, nói với ba người Bạch Hổ rằng mình đã là trưởng lão Đại Hồn Môn và để họ tới Quy Nhất Tông báo tin. Sau khi ba người rời đi, vì thương thế của Dĩ Ti khôi lỗi và vì không chấp nhận chịu thiệt, Vương Lâm quyết định quay lại Đan Hải, trước hết đoạt la bàn trận pháp rồi giết Vân Không."},{"chuong":1753,"tieuDe":"Ẩn Nấp","tomTat":"Vương Lâm xuất hiện trên không trung Đan Hải, thu liễm khí tức rồi dùng cấm chế bổn nguyên bắt chước đại trận bao phủ Đan Hải để hóa thành sương mù ẩn vào tầng sương mù thứ bảy. Trên đường áp sát khu vực gần Lục Ma Châu, hắn thấy lực lượng tuần tra dày đặc, cường giả Không Huyền và nhiều pháp bảo chiến tranh khổng lồ, trong đó có trống lớn đen kịt chứa oan hồn và tu sĩ dung hợp bên trong. Hắn tìm ra trung tâm trận pháp dưới ba cây đại kỳ, nơi nữ tử cầm la bàn, thanh niên mặt trắng và mấy trăm tu sĩ lục y đang canh giữ, đồng thời nhận định la bàn là vật cần đoạt để tiến vào Đan Hải và tìm Vân Không. Qua đối thoại của hai người canh la bàn, Vương Lâm biết Vân Không đã ra tay, Đan Hải sắp biến mất và nửa viên tiên đan trong truyền thuyết có thể lộ ra, ngay sau đó Đan Hải nổi lên chín dòng xoáy khổng lồ. Khi một tổ Lục Ma vệ từ đáy biển trở về, Vương Lâm chớp thời cơ chui vào tai một tu sĩ để trà trộn tiếp cận mục tiêu. Hành động ấy khiến la bàn cảnh báo trong chớp mắt, nữ tử cầm la bàn nghi có kẻ am hiểu ẩn thân xâm nhập và nhờ Triệu sư huynh trợ lực để nghịch chuyển la bàn tra lại biến cố vừa xảy ra."},{"chuong":1754,"tieuDe":"Đan Hải Tiên Đan","tomTat":"Nữ tử cầm la bàn truy ra tung tích Vương Lâm đang nhập thân tu sĩ, nhưng Vương Lâm tiếp tục hóa khói khống chế nam tử trung niên Không Niết sơ kỳ để áp sát nàng. Khi la bàn và ba đại kỳ sắp bóc trần vị trí, hắn kích nổ Vạn Tịnh Hóa Ô Dịch thành hắc thủy, giết nhiều tu sĩ Lục Ma Châu, đồng thời gọi Dĩ Ti khôi lỗi bẻ gãy ba cây đại kỳ. Vương Lâm dùng Định cố định nữ tử và thanh niên mặt trắng, đoạt la bàn, đánh nát nữ tử cả thân thể lẫn Nguyên Thần rồi dùng Huyết Kiếm giết thanh niên họ Triệu. Sau đó hắn lặn xuống đáy biển, dùng cấm chế bổn nguyên xóa thần thức cũ trên la bàn, biến nó thành vật của mình và nắm cấm chế đại trận Đan Hải. Nhờ la bàn, Vương Lâm xác định điểm sáng của Vân Không ở hải vực trung tâm, nhưng khi thấy Đan Hải biến động dữ dội, hắn không vội dùng ba nghìn vạn đạo hồn mà ẩn xuống đáy biển chờ thời cơ. Ở dòng xoáy thứ chín, Vân Không luyện hóa Đan Hải để ngưng tụ nửa hạt tiên đan, thứ được hé lộ là bản chất thật của Đan Hải. Mấy vạn tu sĩ Lục Ma Châu trên bầu trời chờ tiên đan thành hình để phá màn ngăn Thiên Ngưu Châu, trong khi Vân Không tin rằng việc này sẽ giúp hắn áp đảo các thiên tài khác, vào hoàng thành Trung châu và giành tư cách tiến vào tổ miếu."},{"chuong":1755,"tieuDe":"Tiên Đan Băng!","tomTat":"Vân Không tiếp tục ép nước biển Đan Hải co rút và bóp nát một chiếc bình để lấy giọt chất lỏng màu vàng làm vật dẫn ngưng tụ tiên đan. Nhờ vật dẫn này, Đan Hải vượt qua cực hạn một vạn trượng, lộ dấu hiệu nửa hạt tiên đan nhưng trạng thái cực kỳ bất ổn. Vương Lâm đã khống chế trận pháp cấm chế trong Đan Hải nên ẩn được khí tức, chờ đúng lúc tiên đan sắp thành mới hiện thân áp sát Vân Không và dùng Huyết Kiếm chém vào dòng xoáy nước biển. Vân Không phun máu hóa kiếm ảnh chặn nhát đầu, nhưng Vương Lâm đổi vận hành trận pháp để đẩy lui viện binh Lục Ma Châu rồi để hỏa bổn nguyên chân thân cầm Huyết Kiếm tung nhát chém thứ hai. Tiên đan vì vậy nổ sớm giữa Đan Hải, phân thân Vân Không bị lực hủy diệt cuốn tan nát còn Vương Lâm kịp dung nhập thiên địa rời đi. Vụ nổ làm tấm màn ngăn cách Thiên Ngưu Châu sụp đổ, đồng thời khiến Lục Ma Châu cũng nứt đất sụp núi; sau đó dị tượng trâu khổng lồ và bọ cạp hư ảnh lần lượt hiện ra đối đầu."},{"chuong":1756,"tieuDe":"Hồn Nhất Lệnh","tomTat":"Nửa hạt tiên đan do Đan Hải biến thành nổ tung, khiến Đan Hải hoàn toàn biến mất, hơn một vạn tu sĩ Lục Ma Châu tử vong và phân thân Vân Không bị đánh tan. Một hư ảnh khổng lồ kịp thời vung tay áo cứu phần tu sĩ Lục Ma Châu còn sống sót, nhưng bản thân cũng bị thương trước lực hủy diệt. Sau ba ngày, tam đại tông môn Lục Ma Châu vẫn giữ kế hoạch tiến công, lập đại quân bảy vạn tu sĩ tiến vào Thiên Ngưu Châu, với nhóm Không Kiếp đi trước làm tiên phong. Vương Lâm chữa thương trong vùng núi gần Đan Hải nhờ thân thể Đạo Cổ, rồi kiểm tra la bàn cổ kính, cấm chế che giấu và ngọc giản ghi công chém tiên đan. Hắn xóa đoạn bản thân lấy la bàn, giữ ngọc giản làm chứng cứ để đòi tầng thứ chín Đa Trọng Huyễn Thuật từ lão tổ Đại Hồn Môn. Trên đường trở về Đại Hồn Môn, Vương Lâm bắt hạc giấy màu đen và biết Đại Hồn Môn cùng Quy Nhất Tông đã phát Hồn Nhất Lệnh, triệu tập các tông môn chuẩn bị chiến đấu. Cuối chương, bổn tôn Vân Không xuất hiện trên cổ kiếm màu vàng, xác nhận phân thân bị hủy khiến tu vi rơi xuống Không Kiếp sơ kỳ và nuôi hận với Vương Lâm."},{"chuong":1757,"tieuDe":"Dự Đoán","tomTat":"Sau khi thấy con hạc giấy u quang và liên hệ với việc Lục Ma Châu luyện hóa Đan Hải, Vương Lâm nhận ra chiến sự đã vượt khỏi ân oán tông môn, giống một cuộc chiến cấp châu lục. Hắn lấy người tí hon ra định tiếp tục tính toán thiên địa nhưng tự thấy đạo thuật không đủ tính ra chân tướng, nên chọn kiểm chứng dần qua ba lễ vật Đại Hồn Môn và các manh mối đã có. Mười ngày sau, hắn trở về sơn môn Đại Hồn Môn giữa lúc hộ môn đại trận mở sát khí, rồi phối hợp hai trưởng lão và năm đệ tử kiểm tra thân phận bằng lệnh bài, thần thức và máu tươi. Qua lời trưởng lão, hắn biết Lục Ma Châu đã phá màn chắn Thiên Ngưu Châu, từng có tu sĩ lẻn vào Đại Hồn Môn và bị Đông Đức trưởng lão giết, khiến toàn tông giới nghiêm. Bên trong tông môn, đệ tử vận chuyển tài liệu luyện khí, thu hái thảo dược, trưởng lão bế quan chuẩn bị chiến tranh, trong khi Viêm Mạch Phong vẫn im lìm với Phàn San Mộng tĩnh tọa. Vương Lâm không về núi của mình mà tới Thanh Thiên Phong gặp Thanh Ngưu chân nhân, đúng lúc lão vừa dùng Hồn Diễn Đạo tính toán thế cục. Thanh Ngưu chân nhân xác nhận đã nhận ngọc giản của Vương Lâm và nói hắn lập đại công, đồng thời cho biết tam đại tông môn Lục Ma Châu có ba cường giả ngang mình nhưng lão có thể đấu hai người. Sau khi nghe thế cục, Vương Lâm trực tiếp yêu cầu Đa Trọng Huyễn Thuật ở tầng thứ chín Tàng Hồn Các."},{"chuong":1758,"tieuDe":"Quỷ Ám","tomTat":"Thanh Ngưu chân nhân trầm mặc trước yêu cầu của Vương Lâm rồi giải thích Tàng Hồn Các có mười tầng, tầng chín chứa thần thông mạnh nhất Đại Hồn Môn còn tầng mười là nơi ngay cả ông cũng không vào được. Vương Lâm đưa ngọc giản ghi việc mình trảm tiên đan ở Đan Hải, khiến Thanh Ngưu xác nhận hắn lập đại công, chữa khỏi thương thế còn sót lại và đồng ý ban Đa Trọng Huyễn Thuật đầy đủ. Tuy vậy, Thanh Ngưu đặt ba điều kiện trước khi cho Vương Lâm rời Đại Hồn Môn: giết tu sĩ Lục Ma Châu theo số lượng và cảnh giới quy định, rồi tiến vào tầng chín và tầng mười Tàng Hồn Các. Vương Lâm cân nhắc ân tình Đại Hồn Môn đã giúp mình nên nhận lời, sau đó được trao ngọc giản Đa Trọng Huyễn Thuật cùng nhiều tài liệu luyện Quỷ Phàm. Trở về ngọn núi của mình, hắn không để ý sự bất an của Phàn San Mộng mà vào động phủ nghiên cứu ngọc giản. Từ ghi chép về Quỷ Phàm, năm phẩm cấp và tử hồn, Vương Lâm liên tưởng tới chuyện quỷ ám thời còn ở thôn cũ và minh ngộ cốt lõi Đa Trọng Huyễn Thuật là dùng oán khí, bất an và ảo giác để quỷ huyễn người."},{"chuong":1759,"tieuDe":"Lữ Văn Nhiễm","tomTat":"Sau khi Vương Lâm rời Thanh Thiên Phong, Thanh Ngưu chân nhân suy xét cục diện Lục Ma Châu sắp có đại động, rồi triệu đệ tử Không Kiếp trung kỳ Lữ Văn Nhiễm ra nhận lệnh. Lữ Văn Nhiễm nhắc lại chuyện từng cùng Âu Dương Tuệ và Mạnh Chương Hải giao chiến với sứ giả Lục Ma Châu ở Đan Hải, thực chất là làm theo bố trí của Thanh Ngưu và tiên đoán của tổ sư, sau đó được giao bảy ngày nữa đi cùng Vương Lâm tới đệ tam huyệt Thiên Ngưu Châu. Trong thời gian ấy, Vương Lâm bế quan nghiên cứu Đa Trọng Huyễn Thuật, luyện toàn bộ tài liệu thành thân Quỷ Phàm màu đen nhưng còn thiếu tử hồn nên chưa thể hoàn thiện. Hắn tới Quỷ Phong của Đại Hồn Môn để chọn hồn phách, tại đó gặp một nữ tử áo trắng quỳ khóc bên bia mộ của chính mình, không nhớ tên tuổi, chỉ day dứt về thân thể, quê nhà và thân nhân. Dù trên núi còn những hồn phách phẩm chất cao hơn, Vương Lâm bị nỗi bi thương ấy chạm động, đặt tên nàng là Côn Hư rồi thu nàng vào Quỷ Phàm. Sau khi dung nhập tử hồn, Quỷ Phàm đổi thành màu trắng và thỉnh thoảng vọng ra tiếng khóc thê lương. Đến hoàng hôn ngày thứ bảy, Vương Lâm nhận ngọc giản truyền lệnh của Thanh Ngưu, biết Đại Hồn Môn đã âm thầm mở bảy Thiên Ngưu huyệt làm trận pháp cấm chế mượn lực Thiên Ngưu để chống Lục Ma Châu, và hắn được điều tới trấn thủ đệ tam huyệt."},{"chuong":1760,"tieuDe":"Thiên Ngưu Tam Huyệt","tomTat":"Thiên Ngưu thất huyệt và lực lượng thường trú tại Đan Hải được xác nhận là quân bài chưa lật của Đại Hồn Môn, đồng thời lão tổ đời đầu Đại Hồn Môn được nhắc là truyền nhân Đạo Thống cùng sư môn với quốc sư Tiên Tộc hiện nay. Vương Lâm nhận ngọc giản điều động của Thanh Ngưu lão tổ, rời ngọn núi sau khi thu hồi hỏa bổn nguyên chân thân, rồi tới sơn môn hội hợp Lữ Văn Nhiễm, Viêm Loan và Hứa Đông Đức. Lữ Văn Nhiễm tuyên bố nhiệm vụ của bốn trưởng lão là tới Thiên Ngưu đệ tam huyệt trấn thủ, đối kháng đợt xâm lấn của Lục Ma Châu. Trên đường, Vương Lâm triệu hồi Văn Thú để bù tốc độ phi hành đường dài và giữ kín nguồn gốc quê hương khi bị Lữ Văn Nhiễm dò hỏi. Sau bảy ngày, Lữ Văn Nhiễm dùng ngọc giản kích hoạt truyền tống trận cổ do lão tổ đời đầu Đại Hồn Môn tạo ra, đưa cả nhóm tới gần Cực Thiên thảo nguyên và Thiên Ngưu đệ tam huyệt. Tại đây, Đại Hồn Môn đã bố trí một Địa Cung dưới đất với nhiều lớp cấm chế, tập trung gần một vạn tu sĩ gồm tán tu và tu sĩ tông phái phụ cận. Ba lão già tiếp ứng ra nghênh đón, khách khí với Lữ Văn Nhiễm, Viêm Loan và Hứa Đông Đức nhưng xem nhẹ Vương Lâm dù biết hắn là trưởng lão mới của Đại Hồn Môn."},{"chuong":1761,"tieuDe":"Giết Tới!","tomTat":"Tại Cực Thiên thảo nguyên, Vương Lâm bị ba lão già thủ trấn và tu sĩ các tông phái xem nhẹ vì tu vi bề ngoài không cao, nhưng hắn không để tâm và tự chọn động phủ ngoại vi tĩnh tọa. Lữ Văn Nhiễm thầm bất mãn vì từng vì Đại Hồn Môn ẩn thân ở Đan Hải hơn một ngàn năm mà vẫn không được truyền Đa Trọng Huyễn Thuật, còn Viêm Loan nhận ra mâu thuẫn ngầm này nhưng cố ý không nhắc nhở. Khi người Đại Hồn Môn tới, cấm chế Cực Thiên thảo nguyên cùng sáu huyệt còn lại khởi động, khiến Thiên Ngưu thất huyệt lần đầu triển khai hoàn toàn và tạo màn phòng hộ khổng lồ được hơn mười vạn tu sĩ, trận pháp cấm chế và Thiên Ngưu Hồn gia trì. Trong lúc các cường giả Không Kiếp tọa trấn ở Địa Cung, Vương Lâm âm thầm luyện hóa chiếc ô màu lam, tìm hiểu Hồn Dẫn và dùng la bàn cấm chế dò trận, từ đó phát hiện quân Lục Ma Châu đã tới. Hơn một vạn tu sĩ Lục Ma Châu kéo đến, do sáu Không Kiếp dẫn đầu, trong đó hai lão Không Kiếp trung kỳ họ Triệu và họ Trương liên thủ biến hóa người khổng lồ vạn trượng cùng ba thanh phi kiếm đen công kích phòng tuyến. Sương mù đen từ Cực Thiên thảo nguyên dâng lên, ngưng thành Thiên Ngưu rồi nổ tung thành sóng sương mù phản kích quân địch. Lữ Văn Nhiễm dẫn nhóm Không Kiếp xuất chiến, gần vạn tu sĩ phe Thiên Ngưu Châu đồng loạt lao ra, Vương Lâm cũng hòa vào đội ngũ khi đại chiến chính thức bùng nổ."},{"chuong":1762,"tieuDe":"Lưu Chi Nguyên","tomTat":"Vương Lâm hòa vào đại quân một vạn tu sĩ Thiên Ngưu Châu tiến vào chiến trường sương mù tại Cực Thiên thảo nguyên Thiên Ngưu đệ tam huyệt. Ở tầng cao, Lữ Văn Nhiễm giao chiến với lão già họ Trương, còn Viêm Loan, Hứa Đông Đức và một tu sĩ Không Kiếp sơ kỳ tông môn phụ cận hợp lực cản lão già họ Triệu nhờ lợi thế trận pháp. Khi hơn hai vạn tu sĩ hai phe hỗn chiến, Vương Lâm dùng la bàn theo dõi điểm trắng điểm xanh và dùng Huyết Kiếm giết một tu sĩ Lục Ma Châu bất ngờ xuất hiện. Hắn không nhắm vào tu sĩ thường mà lặng lẽ tiến gần khu vực bảy Không Kiếp sơ kỳ đang giao chiến, tự đánh giá độ khó giết Không Kiếp sơ kỳ và cân nhắc các thủ đoạn như khôi lỗi Dĩ Ti, Huyết Kiếm, Dịch Linh Ấn, Đa Trọng Huyễn Thuật và Dẫn Hồn Quy. Lưu Chi Nguyên, trưởng lão Đạo Ma Tông mới bước vào Không Kiếp sơ kỳ, bị sương mù cản thần thức và hút tiên lực nên lui lại để bổ sung. Hắn lấy ra hơn mười quả cầu ánh sáng chứa nữ tử lô đỉnh, định cắn nuốt bằng công pháp song tu hắc liên. Vương Lâm nhận ra thời cơ, dùng Huyết Kiếm đánh lén khiến Lưu Chi Nguyên phải bỏ việc cắn nuốt và gọi hắc liên ra ngăn cản. Chương kết ở khoảnh khắc Lưu Chi Nguyên xoay người trong sát khí và Vương Lâm tiếp tục ra tay."},{"chuong":1763,"tieuDe":"Phục Kiếp!","tomTat":"Khôi lỗi Dĩ Ti từ hắc vụ quanh Vương Lâm lao ra phục kích Lưu Chi Nguyên, phá bảy đóa hắc liên và dùng đầu lưỡi xuyên thủng ngực khiến đối thủ rơi vào nguy cấp khi tiên lực gần cạn. Lưu Chi Nguyên định nuốt quang cầu màu đen để bổ sung, nhưng Vương Lâm dùng tấm buồm mặt quỷ màu trắng nhiễu loạn tâm thần rồi lập tức phối hợp chưởng ấn, hỏa diễm chưởng ấn, khôi lỗi Dĩ Ti và Huyết Kiếm vây sát. Lưu Chi Nguyên phun máu hóa huyết giáp và thi triển Huyết giáp chấn để đánh tan thế công, song vẫn bị phản chấn và bị Vương Lâm áp sát dùng Quyền Đạo Cổ đánh vỡ cánh tay phải, tiếp tục truy kích bằng mười chín quyền. Bị ép tới tuyệt cảnh, Lưu Chi Nguyên lấy chuông đen triệu mấy chục vạn nữ oan hồn, oán khí lan khắp Cực Thiên thảo nguyên khiến các chiến trường Không Kiếp xung quanh biến sắc nhưng không nhìn rõ vì sương mù. Vương Lâm gọi hồ lô chứa hơn ba nghìn vạn đạo hồn, dùng máu mở con đường máu và thi triển Hồn huyễn trở về để triệu hư ảnh La Vân Hải, đệ cửu Tiên Tổ Đại Hồn Môn. La Vân Hải ngưng sát khí thành trường thương đỏ rực, phá thân ảnh nữ tử do oan hồn kết thành, khiến oan hồn phản phệ Lưu Chi Nguyên đến trọng thương. Khi Lưu Chi Nguyên chưa chết và muốn bỏ chạy, Vương Lâm niệm chuỗi thần, yêu, ma, kết bằng cổ đạo vô tiên rồi đánh ra một quyền."},{"chuong":1764,"tieuDe":"Người Tên Vương Lâm","tomTat":"Lưu Chi Nguyên mất thân thể, Nguyên Thần vỡ vụn dưới đòn của Vương Lâm, chỉ còn phần đầu bị Vương Lâm thu đi rồi biến mất khỏi chiến trường. Cái chết của một tu sĩ Không Kiếp sơ kỳ khiến hai phe trên Cực Thiên thảo nguyên chấn động, Lục Ma Châu vội rút quân còn Thiên Ngưu Châu lui về Địa Cung phòng thủ nghiêm mật. Vương Lâm trở lại Địa Cung trong trạng thái bị thương, tự nhận đây là tu sĩ Không Kiếp đầu tiên mình giết và hiểu chiến thắng chỉ đến từ thời cơ, Thiên Ngưu trận pháp cùng cấm chế trên la bàn. Trong đại điện Địa Cung, Lữ Văn Nhiễm, Viêm Loan và các tu sĩ Không Kiếp bàn luận nhưng không xác định được hung thủ, chỉ nghi có cường giả ẩn giấu. Bên ngoài sương mù, phe Lục Ma Châu tra xét và một nữ tử nhận ra dấu vết Đoạn Không cấm trận của Cấm Ma Tông. Lão già họ Triệu liên hệ việc la bàn Đoạn Không cấm biến mất sau kịch biến Đan Hải với trưởng lão Đại Hồn Môn tên Vương Lâm, còn lão già họ Trương vì lo lửa giận Tông chủ Đạo Ma Tông nên quyết ý giết người họ Vương."},{"chuong":1765,"tieuDe":"Khách Không Mời!","tomTat":"Đêm xuống trên Cực Thiên thảo nguyên, chiến trường ban ngày của mấy vạn tu sĩ trở nên tĩnh lặng, thi thể và hồn phách đã bị sương mù cắn nuốt, chỉ còn mùi máu tanh nhạt. Trong động phủ dưới Địa Cung, Vương Lâm dưỡng thương sau khi giết Lưu Chi Nguyên, nhận ra việc giết tu sĩ Không Kiếp cực kỳ gian nan và cân nhắc nhiệm vụ Thanh Ngưu chân nhân giao. Vì đã nhận thủy bổn nguyên, Không Gian Thạch và một lần tính toán, hắn quyết định nhanh chóng hoàn thành điều kiện để cắt ràng buộc với Đại Hồn Môn. Viêm Loan đêm khuya tới thăm dò, nghi Vương Lâm là người giết tu sĩ Không Kiếp của Lục Ma Châu; Vương Lâm không xác nhận, còn nàng đề nghị hợp tác giết địch để chia lợi ích và để lại đan dược trị thương. Hai ngày sau, Lục Ma Châu không tấn công tiếp mà chỉ phái người quan sát, khiến bầu không khí càng căng thẳng. Lữ Văn Nhiễm nghi đối phương chờ viện quân, đồng thời suy đoán người giết Không Kiếp là Vương Lâm nên âm thầm phái lão già họ Chu tới động phủ yêu cầu hắn ra ngoài tuần tra một đêm."},{"chuong":1766,"tieuDe":"Tâm Trạng Trong Đêm","tomTat":"Lão già họ Chu coi thường Vương Lâm, cho rằng hắn chỉ là trưởng lão Đại Hồn Môn nhờ quan hệ, tu vi yếu và bị Lữ Văn Nhiễm đẩy ra ngoài cung điện nên không đáng e ngại. Vì gọi mãi không được đáp, lão phá nát đại môn động phủ, nhưng khi bước vào lại bị ánh mắt và khí tức của Vương Lâm làm kinh hãi đến mức phải lùi ra ngoài. Dưới áp lực của Vương Lâm, lão khai Lữ Văn Nhiễm là người sai khiến; Vương Lâm nhìn về cung điện của Lữ Văn Nhiễm, còn Lữ Văn Nhiễm cũng mở mắt như nhận ra ánh nhìn ấy. Vương Lâm không giết lão già họ Chu vì coi là phạm lần đầu, nhưng trừng phạt bằng một vỗ vai, khiến lão thổ huyết và buộc phải sửa lại cửa động phủ trước khi hắn trở về. Sau đó Vương Lâm không từ chối việc tuần tra, đi lên khỏi lòng đất Cực Thiên thảo nguyên và bước một mình trong đêm. Giữa bóng tối, hắn chạm vào tay phải nơi có Không Gian trữ vật chứa Lý Mộ Uyển đang ngủ, nhớ lại hơn hai ngàn năm tìm kiếm và chiến đấu vì nàng. Chương khép lại bằng suy tưởng của Vương Lâm về ký ức như một chiếc rương trong lòng mỗi người; chiếc rương của hắn vẫn còn, nhưng màn đêm che đi vẻ cô độc và hiu quạnh của hắn."},{"chuong":1767,"tieuDe":"Hứa Đức Tài","tomTat":"Vương Lâm tuần tra ngoài Địa Cung trong đêm mưa, dùng la bàn cấm chế phát hiện các điểm sáng Lục Ma Châu đang đổi hướng bám theo và dần tạo thành thế bao vây. Hắn nhận ra Lữ Văn Nhiễm cố ý phái mình ra ngoài làm mồi nhử, lại thử quay về Địa Cung nhưng bị phản lực ngăn cản, nên quyết định lợi dụng vòng vây để hoàn thành nhiệm vụ Thanh Ngưu lão tổ giao. Phe Lục Ma Châu triển khai truy sát nhiều tầng: hai lão quái Không Kiếp trung kỳ là họ Trương và họ Triệu dẫn hướng, các tu sĩ Không Kiếp sơ kỳ dẫn các đội khác, hậu phương có nữ tu dùng la bàn hư ảo theo dõi vị trí. Hứa Đức Tài, một tán tu Không Kiếp sơ kỳ của Lục Ma Châu, tham chiến vì Đạo Ma Tông hứa cho vào vực sâu tu hành một ngàn năm nếu giết được Vương Lâm. Khi đội của hắn lao tới, Vương Lâm xuất hiện từ bóng tối với Huyết Kiếm, chém giết nhiều tu sĩ và buộc Hứa Đức Tài phóng tín hiệu đầu lâu cầu viện. Hứa Đức Tài quyết định kéo dài thời gian, liên tiếp thi triển sư ảnh trăm vạn ấn ký, bốn người đất khổng lồ và cây hương kình ngư bằng tốc độ ấn quyết khiến Vương Lâm kinh hãi."},{"chuong":1768,"tieuDe":"Thôn Thiên Đạo!","tomTat":"Hứa Đức Tài mở màn bằng cách cắm cây hương xuống đất, trong tích tắc kết gần sáu trăm vạn ấn quyết rồi phát động Nê sát, dùng bùn đất phong bế Vương Lâm. Nhờ tốc độ thi pháp dị thường, hắn liên tiếp thi triển mãng xà độc khí, phi kiếm vàng, người bùn tự bạo, tấm màn hóa sợi tơ, hung thú đầu chó, chất lỏng xanh, hai bàn tay khổng lồ và hư ảnh kình ngư, khiến Vương Lâm rơi vào một trận chật vật hiếm thấy. Vương Lâm dù bị đánh đến thổ huyết, y phục tổn hại và toàn thân tuôn huyết vụ, vẫn dựa vào thân thể Đạo Cổ chống chịu các lớp công kích. Khi hư ảnh kình ngư của Hứa Đức Tài tiếp tục cắn nuốt, Vương Lâm phun viên đá màu đen gọi ra U Minh Thú, để Thiên Đạo của mình nuốt Thiên Đạo kình ngư của đối thủ. Hứa Đức Tài thổ huyết, đau lòng và điên cuồng vì mất Thiên Đạo, còn Vương Lâm nhận ra tốc độ thi pháp của hắn có thể bắt nguồn từ cơ duyên hoặc thần thông hiếm thấy. Thay vì tiếp tục dây dưa, Vương Lâm thu U Minh Thú thành Không Gian Thạch, dịch chuyển rời đi để dụ ba tu sĩ Không Kiếp của Lục Ma Châu rời đội ngũ, rồi xuất hiện tại vị trí đội ngũ vừa bỏ trống nhằm triển khai giết chóc."},{"chuong":1769,"tieuDe":"Kim Thiền Thoát Xác","tomTat":"Bên cạnh Cực Thiên thảo nguyên, nữ tu Không Kiếp dùng la bàn hư ảo theo dõi điểm sáng của Vương Lâm và phát hiện hắn liên tục biến mất rồi xuất hiện cạnh các nhóm tu sĩ Lục Ma Châu, khiến nàng lập tức báo động cho toàn bộ tu sĩ Không Kiếp. Vương Lâm trong lúc bị truy sát đã nuốt huyết nhục và nguyên thần của ba tổ tu sĩ Lục Ma Châu để chữa thương sau trận với Hứa Đức Tài. Hắn nhìn ra trong bốn kẻ truy sát có một tu sĩ sở hữu thần thông tốc độ rất nhanh, rồi dùng một nguyên thần bị xóa ý chí nhập thần trí của mình vào để điều khiển la bàn bay đi làm mồi nhử. Kế kim thiền thoát xác khiến hắn thoát khỏi vai con mồi, đồng thời kéo hai lão quái Không Kiếp trung kỳ tách xa hai tu sĩ Không Kiếp sơ kỳ. Trong lúc chờ thời cơ, Vương Lâm nhận ra Không Gian Thạch có thể tăng mạnh năng lực cắn nuốt của U Minh Thú và lần đầu đưa thân thể vào bên trong viên đá. Tại không gian trong Không Gian Thạch, hắn dùng ô màu lam, hồ lô ba nghìn vạn đạo hồn, kim ấn Huyền La, Quỷ Phàm, Văn Vương, khôi lỗi Dĩ Ti cùng các bổn nguyên để dựng thành sát trận. Khi la bàn mồi nhử bị phá và tiếng gào phẫn nộ của hai lão quái truyền tới qua tia thần thức, Vương Lâm lập tức biến mất để bắt đầu dẫn địch vào bẫy."},{"chuong":1770,"tieuDe":"Vây Hứa!","tomTat":"Trên Cực Thiên thảo nguyên, Hứa Đức Tài rời khỏi chiến trường trong trạng thái nguyên thần uể oải vì Thiên Đạo tâm thần tương liên đã bị Vương Lâm nuốt, khiến hắn vừa bị thương vừa căm hận đối phương. Khi thấy Vương Lâm xuất hiện phía sau, hắn tưởng đối phương tự lộ sơ hở nên lập tức truy đuổi, nhưng khi vào phạm vi ngàn trượng thì bị kéo vào Không Gian Thạch giấu trong cỏ dại lầy lội. Nữ tử Không Kiếp sơ kỳ của Lục Ma Châu phát hiện điểm sáng đại biểu Hứa Đức Tài biến mất trên la bàn, vội truyền tin cho ba tu sĩ Không Kiếp, khiến lão Trương và lão Triệu nhận ra Vương Lâm dùng kế kim thiền thoát xác để tách người. Cùng lúc đó, sương mù đen dâng lên trên thảo nguyên, Lữ Văn Nhiễm dẫn mấy ngàn tu sĩ Thiên Ngưu Châu trong Địa Cung phát động lần công kích thứ hai, vây chặn ba tu sĩ Không Kiếp Lục Ma Châu. Bên trong Không Gian Thạch, Hứa Đức Tài rơi vào không gian do Vương Lâm chỉ định, nơi có hỏa diệm sơn, lôi hải, mây đen và tuyết đen. Vương Lâm dùng nhân quả, sinh tử và chân giả bổn nguyên hóa kiếm, lần lượt phá u hồn, mãng xà và ép Hứa Đức Tài đánh ra chiêu thứ ba chưa hoàn thành, khiến ưu thế tốc độ thi pháp của hắn lần đầu bị áp đảo. Sau đó Vương Lâm dùng hỏa diệm sơn bao phủ Hứa Đức Tài, chuyển vào lôi hải để lôi hỏa hợp kích, rồi lấy máu huyết ngưng tụ thủy bổn nguyên, dung hợp ba loại lực lượng thành sát cục hủy diệt trong khi ba hư bổn nguyên tiếp tục hóa kiếm lao tới."},{"chuong":1771,"tieuDe":"Đèn Lồng!","tomTat":"Trong sát trận, sáu đạo bổn nguyên của Vương Lâm hợp lực đánh Hứa Đức Tài trọng thương, nhưng chiếc đèn lồng trên đỉnh đầu đối phương tỏa sáng bảo hộ khiến hắn chưa chết. Nhận ra Hứa Đức Tài khó giết hơn Lưu Chi Nguyên, Vương Lâm liên tục dùng Định Thân Thuật dù bị phản phệ để cắt nhịp thi triển thần thông của đối thủ. Hắn tiếp tục dùng cấm chế tuyết đen, Quỷ Phàm và ba ngàn vạn đạo hồn cuốn Hứa Đức Tài lên bầu trời màu lam để oanh sát. Không chờ kết quả, Vương Lâm dồn thêm hỏa bổn nguyên chân thân, Thất Thải Thuật, Dịch Linh Ấn, Phần Giới Cổ Tán và nhiều tiên thuật khiến Hứa Đức Tài phun máu, mất cánh tay nhưng vẫn được đèn lồng giữ mạng. Ở đợt chém giết thứ ba, khôi lỗi Dĩ Ti đánh nát thân thể Hứa Đức Tài, còn Văn Vương cuốn lấy nguyên thần hắn nhưng bị ánh sáng đèn lồng ngăn nuốt trọn. Cuối chương, Vương Lâm rút Huyết Kiếm chém xuống, nhắm vào việc cắt đứt liên hệ giữa nguyên thần Hứa Đức Tài và pháp bảo đèn lồng."},{"chuong":1772,"tieuDe":"Tốc Thần Quyết","tomTat":"Vương Lâm dùng Huyết Kiếm đánh tắt đèn lồng phòng hộ nguyên thần của Hứa Đức Tài, tiếp tục công kích đến khi đối phương suy kiệt rồi thu nguyên thần vào Không Gian trữ vật. Sau trận, hắn thổ huyết dưỡng thương ba ngày, được Văn Vương hộ pháp, còn Dĩ Ti lấy cánh tay Hứa Đức Tài để dung hợp khôi phục đôi tay. Vương Lâm luyện hóa đèn lồng của Hứa Đức Tài, biết ánh nến còn thì nguyên thần bất diệt và thu nó vào cơ thể để thủ hộ nguyên thần. Hắn soát hồn Hứa Đức Tài trong ba canh giờ, phát hiện Tốc Thần Quyết có nguồn gốc từ thiên thạch thiên ngoại, cơ chế mở chín thần mạch để tăng tốc thi triển thần thông. Nguyên thần Hứa Đức Tài sau khi chết lại tự sinh quỷ hồn vì oán khí, khiến Vương Lâm kinh ngạc rồi lập tức truy bắt và thu giữ làm cơ duyên cho Đa Trọng Huyễn Thuật. Sau khi nghiên cứu thuật mới, Vương Lâm thu hồ lô chứa Đạo Hồn còn một nửa, chiếc ô màu lam, Văn Vương và Dĩ Ti rồi rời không gian chiến đấu. Trên Cực Thiên thảo nguyên, chiến trường sương mù vẫn hỗn loạn; Lục Ma Châu mất hai Không Kiếp sơ kỳ nên hai lão quái trung kỳ họ Trương và họ Triệu bị Lữ Văn Nhiễm cùng nhiều tu sĩ ép vào thế chật vật."},{"chuong":1773,"tieuDe":"Trương Đạo Tông!","tomTat":"Vương Lâm hiện thân từ Không Gian Thạch trên thảo nguyên gần chiến trường, thu vật này lại và nhận ra cách dùng nó rất nguy hiểm vì điểm rơi khó kiểm soát. Hắn tiến về chiến trường Thiên Ngưu Châu — Lục Ma Châu nhưng không muốn thật sự dấn thân vào chiến tranh, chỉ muốn hoàn thành ba điều kiện của Thanh Ngưu lão tổ để trả ân Đại Hồn Môn. Trong chiến trường còn chưa tới bốn ngàn tu sĩ, hắn cứu lão già tóc bạc Thiên Ngưu Châu khỏi một tu sĩ Lục Ma Châu Không Huyền trung kỳ, giết đối phương và phong ấn nguyên thần vào thân để mở thần mạch Tốc Thần Quyết. Sau đó Vương Lâm tiếp tục giết và phong ấn nguyên thần chín tu sĩ Không Huyền, hiểu thêm cơ chế dòng xoáy tăng tốc thi triển thần thông nhưng cũng nhận ra muốn mở thần mạch thứ hai cần nguyên thần tu vi cao hơn. Khi hắn cân nhắc rời đi, Trương Đạo Tông bất ngờ phục kích bằng lục mang, dùng thần niệm khóa chặt và một tiếng “Truất” phong bế thiên địa, khiến Vương Lâm không thể dung nhập thoát thân. Trương Đạo Tông tự xưng đã đợi Vương Lâm nhiều ngày vì cái chết của Lưu Chi Nguyên, còn Vương Lâm lập tức gọi Văn Thú phi hành bỏ chạy trong lúc khoảng cách giữa hai bên nhanh chóng bị rút ngắn."},{"chuong":1774,"tieuDe":"Kịch Biến!","tomTat":"Vương Lâm bị Trương Đạo Tông truy sát trong tình thế cực kỳ nguy hiểm, vì chênh lệch với lão quái Không Kiếp trung kỳ quá lớn và thiên địa đã bị phong ấn khiến hắn không thể na di. Trương Đạo Tông rời chiến trường không phải hành động tùy hứng, mà nằm trong kế hoạch phục sát của Lục Ma Châu nhằm dụ Vương Lâm lộ diện rồi dùng viện quân ẩn giấu từ trước để giết hắn. Bốn Lục Ma sứ giả mang khí tức Không Kiếp trung kỳ xuất hiện cùng dị tượng bọ cạp xanh biếc, làm Lữ Văn Nhiễm lập tức ra lệnh tu sĩ Thiên Ngưu Châu rút về Địa Cung và phong kín phòng tuyến. Vương Lâm nhận ra nếu chậm một bước thì mình sẽ bị sáu lão quái Không Kiếp trung kỳ hợp vây, nên cưỡi Văn Thú lao xuống mặt đất trong lúc Viêm Loan, Hứa Đông Đức và các tu sĩ Không Kiếp Thiên Ngưu Châu cũng bị thương rút lui. Khi Trương Đạo Tông đánh tới, Vương Lâm tự bạo chiếc ô màu lam để cản một kích và mượn lực rơi xuống gần đại địa hơn. Lữ Văn Nhiễm sau khi vào đại địa nhìn thấy Vương Lâm chưa kịp tới nhưng vẫn lựa chọn phong bế trận pháp, khiến cửa sống của Vương Lâm gần như khép lại. Trong khoảnh khắc cuối, Vương Lâm ném hồ lô chứa gần ba ngàn vạn đạo hồn và cho nổ, buộc Trương Đạo Tông cùng một Lục Ma sứ giả khựng lại. Nhờ khoảng thời gian cực ngắn đó, hắn vượt qua năm mươi trượng cuối cùng và dung nhập vào đại địa ngay trước khi trận pháp Địa Cung hoàn toàn phong bế."},{"chuong":1775,"tieuDe":"Hồn Khải!","tomTat":"Vương Lâm kịp chui vào lòng đất trước khi khu vực bị phong bế hoàn toàn, nhưng phải tự bạo hồ lô chứa ba nghìn vạn đạo hồn để đổi lấy sinh cơ. Trở lại Địa Cung Thiên Ngưu đệ tam huyệt, hắn đau lòng vì tổn thất, ghi thù Trương Đạo Tông và Lữ Văn Nhiễm, đồng thời nhận ra Lục Ma Châu có thể đã phát hiện chuyện Đan Hải và nhắm riêng vào mình. Trong Địa Cung chỉ còn khoảng một ngàn tu sĩ chạy thoát, trận pháp phía trên liên tục bị công kích khiến nhân tâm tan rã, nhiều người bàn tới bỏ chạy hoặc đầu hàng. Lữ Văn Nhiễm xuất hiện trong tình trạng mất một cánh tay, cùng Viêm Loan, Hứa Đông Đức, ba tu sĩ Không Kiếp và lão già họ Chu; hắn giết một nam tử trung niên vừa nói đến đầu hàng để trấn áp đám đông. Theo lệnh Lữ Văn Nhiễm, lão già họ Chu công bố thủ đoạn cuối cùng của Thiên Ngưu đệ tam huyệt là dùng toàn bộ tu vi mọi người gọi hồn phách Thiên Ngưu hóa thành Hồn Khải. Người mặc Hồn Khải có thể được Thiên Ngưu nhập thân và tăng tu vi khủng bố trong thời gian ngắn, còn các Đại Tôn đã chọn Lữ Văn Nhiễm làm người mặc. Vương Lâm không tin Lữ Văn Nhiễm sẽ gánh nguy hiểm nếu không có lợi, trong khi Viêm Loan lộ vẻ khinh bỉ trước lời lẽ bi tráng của hắn."},{"chuong":1776,"tieuDe":"Ta Không Đồng Ý!","tomTat":"Trong Địa Cung, Viêm Loan và các tu sĩ nhận ra Hồn Khải do hồn phách Thiên Ngưu hóa thành là cơ duyên cực lớn, nhưng việc gọi hồn chỉ được phép khi Thiên Ngưu Châu gặp nguy cơ xâm lấn. Lữ Văn Nhiễm lợi dụng tình thế Lục Ma Châu xâm lấn để chủ trì nghi thức, ép hơn ngàn tu sĩ góp tu vi và khiến các tu sĩ Không Kiếp, Viêm Loan, Hứa Đông Đức không thể tranh đoạt. Lão già họ Chu lập ấn huyết sắc, mở dòng xoáy thông tới nơi phong ấn Thiên Ngưu, rồi dùng máu của hơn ngàn tu sĩ ngưng thành dây chuyền khóa kéo Thiên Ngưu Hồn. Tiếng rống oán hận của Thiên Ngưu vang khắp Địa Cung, làm nhiều tu sĩ trọng thương uể oải, trong khi Vương Lâm ở động phủ âm thầm quan sát và chờ đợi. Khi dây chuyền không kéo tiếp được, lão già họ Chu cùng các Nguyên Thần Không Kiếp hợp lực kéo hư ảnh Thiên Ngưu ra ngoài. Hư ảnh ấy co rút thành một bộ Hồn Khải tỏa khí tức linh hồn cường đại, khiến Lữ Văn Nhiễm cười lớn lao tới nhận lấy. Đúng lúc đó, Vương Lâm hóa thành cầu vồng từ động phủ xông ra, tuyên bố không đồng ý để Hồn Khải thuộc về Lữ Văn Nhiễm."},{"chuong":1777,"tieuDe":"Đầu Lâu!","tomTat":"Lữ Văn Nhiễm dùng áp lực tập thể để phủ nhận tư cách nhận Hồn Khải của Vương Lâm, nhưng Viêm Loan lập tức công khai ủng hộ Vương Lâm, sau đó Hứa Đông Đức cũng đứng về phía hắn. Lữ Văn Nhiễm tiếp tục chất vấn ba tu sĩ Không Kiếp của tông môn phụ cận, khiến họ vì sợ đắc tội cả hai phía mà im lặng, còn hơn một ngàn tu sĩ trong Địa Cung không dám lên tiếng. Khi bị hỏi vì sao phản đối Lữ Văn Nhiễm nhận Hồn Khải, Vương Lâm nêu thẳng rằng cống hiến của đối phương trong trận chiến không đủ, buộc Lữ Văn Nhiễm phải kể công lao trước đám đông. Vương Lâm sau đó lấy đầu lâu Lưu Chi Nguyên ra, xác nhận đó là tu sĩ Không Kiếp Lục Ma Châu và tuyên bố chính mình giết hắn, khiến Địa Cung chấn động và dư luận bắt đầu nghiêng về việc Vương Lâm có tư cách hơn. Viêm Loan, Hứa Đông Đức, ba tu sĩ Không Kiếp phụ cận và lão già họ Chu đều kinh hãi trước vật chứng này. Lữ Văn Nhiễm nhận ra chiến công ấy có thể làm Vương Lâm ngang hàng mình nên lập tức cáo buộc Vương Lâm nhặt đầu lâu do một tiền bối thần bí giết rồi đem tới giả mạo công lao."},{"chuong":1778,"tieuDe":"Thẹn Quá Hóa Giận!","tomTat":"Lữ Văn Nhiễm biết bước cuối dung hợp Hồn Khải cần ý niệm của đông đảo tu sĩ trong Địa Cung nên cố ý bôi nhọ Vương Lâm, vu hắn giả mạo chiến công và xúc phạm anh hồn tử trận. Lời kích động khiến hơn một ngàn tu sĩ dao động, trong khi các tu sĩ Không Kiếp vẫn âm thầm quan sát. Vương Lâm không tranh cãi nhiều mà lấy đầu lâu Hứa Đức Tài ra, chứng minh hắn đã giết thêm một Đại Tôn Không Kiếp sơ kỳ của Lục Ma Châu, khiến toàn trường chấn động. Khi Lữ Văn Nhiễm tiếp tục chống chế rằng đầu lâu có thể do Vương Lâm nhặt được, Vương Lâm lấy luôn quỷ hồn Hứa Đức Tài ra, làm lời vu cáo gần như sụp đổ. Lão già họ Chu sau đó công bố bước cuối dung hợp Hồn Khải là để các tu sĩ tập trung ý niệm vào người được lựa chọn, khiến cuộc tranh đoạt chuyển sang lựa chọn công khai. Không cam lòng mất Hồn Khải, Lữ Văn Nhiễm thẹn quá hóa giận lao tới định giết Vương Lâm, còn Vương Lâm đã phòng bị, lập tức lùi lại và vận Tốc Thần Quyết. Cùng lúc đó, lão giả tóc bạc Cực Thiên thảo nguyên kêu gọi người của mình chọn Vương Lâm, Viêm Loan và Hứa Đông Đức cũng ra tay về phía Lữ Văn Nhiễm."},{"chuong":1779,"tieuDe":"Hồn Khải Nhận Chủ","tomTat":"Lữ Văn Nhiễm nhận ra mình đã mất tiên cơ nên bất chấp hơn một ngàn tu sĩ trong Địa Cung, quyết giết Vương Lâm ngay trước mặt mọi người. Vương Lâm vừa lùi vừa dùng thần mạch tăng tốc vận chuyển tu vi, liên tiếp thi triển trường thương bảy màu, Dịch Linh Ấn, Phần Giới Cổ Tán, Tàn Dạ, Lưu Nguyệt, Hô Phong Hoán Vũ, Tát Đậu Thành Binh Sơn Băng Địa Liệt và Âm Nguyệt Hữu Tình để ép Lữ Văn Nhiễm. Lữ Văn Nhiễm dùng tu vi Không Kiếp trung kỳ phá tan các lớp thần thông, phun máu hóa hai phân thân huyết sắc cản Viêm Loan và Hứa Đông Đức rồi triệu bánh xe chín răng cưa đánh xuống. Vương Lâm quyết đánh cược bằng Tam Mệnh Thuật để tranh cơ duyên Hồn Khải, thi triển Tê Thiên bẻ gãy bốn răng bánh xe nhưng vẫn bị năm răng còn lại đánh trúng tới phun sương máu. Nhờ thân thể cường hãn và đèn lồng hộ thân, hắn không bị cắt đôi như Lữ Văn Nhiễm tưởng mà còn nhanh chóng hồi phục. Khi Lữ Văn Nhiễm định tung một chưởng kết liễu, Thiên Ngưu Hồn Khải ở xa phát u quang, hóa vô số tơ đen lướt qua Lữ Văn Nhiễm để bao quanh Vương Lâm, khiến Lữ Văn Nhiễm bị khí tức bộc phát đánh bay trong sợ hãi và không cam lòng."},{"chuong":1780,"tieuDe":"Giết Lữ Văn Nhiễm!","tomTat":"Trong Địa Cung, vô số sợi tơ đen từ Thiên Ngưu Hồn Khải cuốn quanh Vương Lâm, nghiền nát bánh xe răng cưa của Lữ Văn Nhiễm và kết thành hắc giáp bao phủ toàn thân hắn. Khí tức Vương Lâm nhờ Hồn Khải liên tục tăng vọt, vượt qua Không Huyền, trải qua biến hóa Huyền Kiếp an toàn và tạm thời bước vào Không Kiếp sơ kỳ, khiến Viêm Loan, Hứa Đông Đức cùng các tu sĩ chứng kiến đều rung động. Lữ Văn Nhiễm vì ghen ghét mà phát cuồng công kích nhưng không phá được hắc giáp, trong khi tâm thần hắn bị Quỷ Phàm Đa Trọng Huyễn Thuật của Vương Lâm dẫn phát hình ảnh nữ tử bạch y khóc thảm. Khi hư ảnh Thiên Ngưu mở mắt gầm vang, tiếng gầm chấn động Địa Cung, Cực Thiên thảo nguyên và làm các tu sĩ Lục Ma Châu phía trên kinh sợ. Vương Lâm chịu ảnh hưởng hung tính của Hồn Khải, lần lượt đánh nát thân thể và Nguyên Thần Lữ Văn Nhiễm; dù đối phương viện thân phận trưởng lão Đại Hồn Môn và đệ tử Thanh Ngưu lão tổ, hắn vẫn một chưởng diệt sạch hình thần. Sau khi giết Lữ Văn Nhiễm, Vương Lâm cảm nhận bản nguyên trong người đã hòa thành huyết mạch và thân thể, rồi lạnh lùng gọi tên Trương đạo tông, dung hợp với hư ảnh Thiên Ngưu lao đi."},{"chuong":1781,"tieuDe":"Thất Thải Tam Biến!","tomTat":"Trên Cực Thiên thảo nguyên, Trương Đạo Tông, lão già họ Triệu và bốn Lục Ma sứ giả đều cảm nhận khí tức cường hãn từ sâu dưới đất bộc phát. Bốn Lục Ma sứ giả nhận ra đó là uy áp của người được Thiên Ngưu Hồn tán thành nên lập tức tản ra, phun máu, gọi bốn bọ cạp màu lục và ngưng Lục Ma kính hiện cảnh Lục Ma Châu để trấn áp khu vực. Dưới lòng đất, Vương Lâm đang ở trạng thái Hồn Khải, muốn giết ba lão quái Không Kiếp trung kỳ theo nhiệm vụ của Thanh Ngưu chân nhân nhưng cũng biết không thể bỏ lại hơn ngàn tu sĩ đã góp máu và tu vi cho Hồn Khải. Khi tiếp cận mặt đất, hắn cảm nhận sự căm ghét của Thiên Ngưu Hồn đối với bọ cạp lục khí, từ đó suy đoán Thiên Ngưu và Lục Ma Hạt Hồn từng có thù cũ trước khi bị Tiên Tổ phong ấn. Vương Lâm đổi hướng, dùng Tê Thiên với tu vi Không Kiếp sơ kỳ tạm tăng và lực lượng Đạo Cổ để xé nát một Lục Ma Hạt Hồn, khiến mặt đất phía tây Cực Thiên thảo nguyên nứt vỡ và một Lục Ma sứ giả phun máu. Sau đó hắn thi triển Thất Thải Thương, lần lượt lộ đệ nhất biến, đệ nhị biến và đệ tam biến, xác lập tam biến là cực hạn mà Thất Thải Tiên Tôn thời mạnh nhất có thể đánh ra. Thất Thải tam biến va vào một bọ cạp khác gây sụp đổ lớn dưới lòng đất, nhưng Vương Lâm nhận ra Hồn Khải chỉ tăng tu vi chứ không tăng thân thể, nên quyết định tiếp tục dùng hai bọ cạp còn lại để thử nghiệm thần thông khác."},{"chuong":1782,"tieuDe":"Tàn Dạ Biến!","tomTat":"Sau khi được Thiên Ngưu tán thành và khoác Thiên Ngưu Hồn Khải, Vương Lâm truy kích hai bọ cạp màu lục đang rút lui, chiến lực tạm thời tăng tới gần Không Kiếp hậu kỳ. Hắn nhớ tới Động phủ giới, Thất Thải đạo nhân, Chiến lão quỷ và càng tin Tiên Cương đại lục có phương pháp khiến Lý Mộ Uyển thức tỉnh. Vương Lâm thi triển Dịch Linh Ấn, chưởng ấn khổng lồ biến thành sáu ngón như Ma Đạo đại thủ ấn, giết hơn một ngàn tu sĩ Lục Ma Châu, trọng thương Trương Đạo Tông, lão già họ Triệu và hai nữ tu Không Kiếp sơ kỳ, đồng thời chấn nát hai bọ cạp dưới lòng đất. Bốn Lục Ma sứ giả dùng Lục Ma kính mời Lục Ma Hạt Hồn, tạo hình chiếu Lục Ma Châu phủ lên Cực Thiên thảo nguyên để trấn áp hắn và tính kéo dài đến khi lực lượng Thiên Ngưu hết thời hạn. Trong lòng đất, Vương Lâm dùng Phần Giới Cổ Tán tạo hỏa tán và biển lửa nhưng nhận ra thần thông này chưa biến hóa như mong đợi. Cuối cùng hắn quyết định thử thần thông tự sáng tạo Tàn Dạ Biến, khiến hắc ám, biển dữ, gió lạnh và mặt trời bình minh chứa lực lượng thái sơ quy tắc xuất hiện, rồi nhìn thấy cảnh tượng khiến hắn sững sờ."},{"chuong":1783,"tieuDe":"Tín Thuật!","tomTat":"Vương Lâm cảm nhận vầng mặt trời trong bóng tối của Tàn Dạ và dần nhận ra căn nguyên của thần thông này là tín niệm nghịch thiên của chính mình. Chương khẳng định Tàn Dạ được hắn sáng tạo vì không buông bỏ Lý Mộ Uyển, vì muốn xé màn đêm che phủ thế giới và tìm ánh sáng có thể giúp nàng sống lại. Trương Đạo Tông, lão già họ Triệu và bốn Lục Ma sứ giả nhìn ra khí tức ấy là tín thuật, cấp độ vượt trên pháp thuật và đạo thuật, vốn chỉ Đại Thiên Tôn mới nắm giữ. Vương Lâm tuyên tín niệm rằng sau đêm tối nhất định có ánh sáng, rồi Tàn Dạ bùng phát thành tín thuật thứ nhất của hắn. Ánh sáng Tàn Dạ khiến hai nữ tu Không Kiếp sơ kỳ hình thần câu diệt, làm bổn tôn lão già họ Triệu tiêu tán và đánh Trương Đạo Tông tan thân, chỉ còn Nguyên Thần miễn cưỡng đào thoát. Lục Ma kính quanh bốn Lục Ma sứ giả vỡ nát, hình chiếu Lục Ma Châu sụp đổ, không gian trở lại Cực Thiên thảo nguyên. Sau khi phá cục, Vương Lâm mặc áo giáp đen bước ra khỏi mặt đất, tóc bạc tung bay và khí tức kinh khủng bao phủ toàn thân."},{"chuong":1784,"tieuDe":"Hồn Khải Tán","tomTat":"Sau khi bị cuốn ra không trung, bốn Lục Ma sứ giả kinh hãi chia nhau bỏ chạy theo bốn hướng, dùng hạc giấy màu lục, phất trần màu trắng, huyết độn và hóa thân thành cơn lốc để thoát khỏi Vương Lâm. Vương Lâm nhớ yêu cầu của Thanh Ngưu chân nhân là giết ba tu sĩ Không Kiếp trung kỳ nên lập tức truy sát, trước hết dùng lôi bản nguyên và cấm chế bản nguyên tạo lưới sét phong ấn kẻ hóa cơn lốc xuống mặt đất. Hắn tiếp tục đuổi theo Lục Ma sứ giả cưỡi hạc giấy, người này nhận ra tín thuật của Vương Lâm là chuyện trọng đại cần báo cho lão tổ, nhưng bị Vương Lâm dùng cầu tám đạo bản nguyên phá Lục Ma nhập thể rồi lấy Huyết Kiếm chém chết cả thân thể lẫn Nguyên Thần. Vương Lâm lại truy về phương bắc, dùng Định thân giữ kẻ đang huyết độn từ rất xa để Huyết Kiếm đánh nát thân thể, còn Thiên Ngưu Hồn nuốt lục khí hình bọ cạp thoát ra từ thi thể. Khi đã phong ấn một người và giết hai người, khí tức Vương Lâm tụt mạnh vì Hồn Khải sắp hết thời hạn, nên hắn bỏ qua Lục Ma sứ giả cuối ở phía nam, quay lại xử lý người bị phong ấn để hoàn thành mục tiêu ba mạng. Sau khi hút máu ba tu sĩ Không Kiếp trung kỳ, Huyết Kiếm hiện ký hiệu cổ xưa thuộc Cổ Tộc, còn Thiên Ngưu Hồn Khải tan thành tơ đen và ngưng thành biểu tượng Thiên Ngưu màu đen bên phải mặt Vương Lâm khi tu vi hắn trở lại Không Linh hậu kỳ. Vương Lâm trở về Địa Cung trong trạng thái suy yếu, nói ngắn gọn về chiến quả khiến hơn một ngàn tu sĩ và Viêm Loan chấn động trước việc lực lượng Lục Ma Châu trên Cực Thiên thảo nguyên gần như bị quét sạch. Hắn vào động phủ, triệu khôi lỗi Dĩ Ti, phong kín nơi ở rồi thổ huyết bế quan, còn những tu sĩ bên ngoài im lặng kính sợ Thiên Ngưu Hồn Khải và lần lượt tản đi chữa thương."},{"chuong":1785,"tieuDe":"Kế Hoạch Tuyệt Mật!","tomTat":"Sau trận chiến ở Cực Thiên thảo nguyên, Địa Cung rơi vào bầu không khí yên lặng kéo dài khi mọi người tận mắt thấy chiến trường tan hoang và càng thêm kính sợ Vương Lâm. Trong ba tháng tiếp theo, không có nhiệm vụ mới từ Đại Hồn Môn và Quy Nhất Tông, còn Vương Lâm một mình bế quan chữa thương, tiêu hóa cảm ngộ khi từng mặc Hồn Khải và nghiên cứu lại Tàn Dạ. Hắn dần nhận ra nếu không có Hồn Khải thì Tàn Dạ không còn giữ được tính chất tín thuật như trước. Sau đó thiên địa đột ngột chấn động, ký hiệu Thiên Ngưu Hồn trên mặt hắn phát tác, cho hắn cảm nhận nỗi bi ai dữ dội và nhìn thấy một người mặc Hồn Khải ở huyệt khác bị bàn tay đỏ thẫm đánh chết, khiến một huyệt trong hệ thống Thiên Ngưu thất huyệt sụp đổ. Hai tháng sau, những chấn động tương tự lại xuất hiện thêm hai lần, báo hiệu tình thế chiến tranh xấu đi nhanh chóng. Đến ngày thứ bảy sau đợt biến động, Âu Dương Chân của Quy Nhất Tông đến Địa Cung truyền lệnh rút toàn bộ Thiên Ngưu đệ tam huyệt về Thiên Loan Sơn. Ông đồng thời báo rằng đệ nhất, đệ nhị và đệ thất huyệt đã bị Lục Ma Châu hủy diệt, rồi mời Vương Lâm dùng Truyền Tống Trận trở về Quy Nhất Tông để tham gia một kế hoạch tuyệt mật."},{"chuong":1786,"tieuDe":"Kẻ Hư Hỏng","tomTat":"Âu Dương Chân báo cho Vương Lâm rằng Thiên Ngưu đệ nhất, đệ nhị và đệ thất huyệt đều đã bị hủy, rồi giao ngọc giản giúp hắn dùng Truyền Tống Trận tới Quy Nhất Tông theo một kế hoạch tuyệt mật. Vương Lâm từ biệt Viêm Loan và các tu sĩ Không Kiếp, rời Thiên Ngưu đệ tam huyệt; sau đó lực lượng phòng thủ tại Địa Cung và Cực Thiên thảo nguyên cũng rút đi, kết thúc phòng tuyến này. Khi tới Quy Nhất Tông, hắn ban đầu bị tu sĩ nơi đây kiểm tra, nhưng nhờ Thiên Ngưu ấn ký và khí tức Thiên Ngưu Hồn nên được cung kính tiếp nhận như Thiên Ngưu sứ giả. Ngay sau đó Đường Giai từ Hưu Sanh Môn, Thiên Ngưu đệ lục huyệt, Thương Minh Sơn cũng truyền tống tới, khiến Vương Lâm chú ý vì dung mạo nàng có vẻ quen thuộc. Đường Giai lại hiểu lầm ánh mắt và lời nói của hắn là kiểu trêu ghẹo cũ kỹ, từ đó coi hắn là kẻ hư hỏng. Hai người được dẫn vào đại điện trung tâm Quy Nhất Tông, nơi một lão già tóc bạc và một thanh niên mang Thiên Ngưu ấn ký đã chờ dưới chiếc chuông lớn; thanh niên vốn lười biếng lập tức khiếp sợ đứng bật dậy khi nhìn thấy Vương Lâm phía sau Đường Giai."},{"chuong":1787,"tieuDe":"Bất Công!","tomTat":"Vân Dật Phong bất ngờ dùng tay hóa kim đao thử sức Vương Lâm ngay khi tái ngộ, khiến những người xung quanh kinh hãi lùi xa. Vương Lâm bình thản thi triển Định Thân Thuật, làm thiên địa và thế công ngưng lại rồi phá kim đao, qua đó cho thấy chênh lệch giữa hai người sau nhiều năm. Vân Dật Phong lộ thân phận người Quy Nhất Tông, ôm lại cố nhân từng vừa là địch vừa là bạn trong động phủ giới. Tông chủ Quy Nhất Tông từ đại điện lên tiếng, phong tỏa quảng trường bằng cấm chế và triệu tập bốn người giữ Thiên Ngưu huyệt. Ông công bố Thiên Ngưu bảy huyệt đã mất ba, ba sứ giả tử vong, rồi lần lượt ban thưởng cho Biên Vân, Đường Giai và Vân Dật Phong bằng chức vị, chí bảo, quyền lợi hoặc truyền thừa. Riêng Vương Lâm chỉ được Ngũ Hành Khải hỏa hệ, ít hơn ba người còn lại, khiến hắn lạnh mắt cắt lời. Tông chủ vẫn công bố nhiệm vụ bí mật: bốn người phải đi Lục Ma Châu, lẻn vào Lục Ma Miếu Vũ, hủy Lục Ma yêu tượng và trọng thương Lục Ma Hồn. Sau khi nói xong, Tông chủ mới quay lại hỏi Vương Lâm còn lời gì cần nói."},{"chuong":1788,"tieuDe":"Phản Bội Thiên Ngưu Châu!","tomTat":"Vương Lâm công khai chất vấn Tông chủ Quy Nhất Tông vì những người khác được hai phần thưởng còn hắn chỉ được Ngũ Hành Hỏa Khải, nhưng Tông chủ viện lý do tu vi hắn thấp nhất rồi thu hồi Hỏa Khải. Khi hắn hỏi bằng chứng thương nghị, đại điện đưa ra một sợi tóc trắng hóa thành thân ảnh Thanh Ngưu lão tổ, khiến hắn nhận ra đó chỉ là một tia thần thức và hiểu Đại Hồn Môn cũng đã bị đặt vào thế đồng thuận. Tông chủ tuyên bố sẽ mở đại trận bất động để đưa bốn người vào Lục Ma Châu nhưng yêu cầu họ lưu lại mệnh hồn; Vân Dật Phong, Biên Vân và Đường Giai lần lượt giao ra, còn Vương Lâm cự tuyệt và muốn trở về Đại Hồn Môn gặp lão tổ trước. Khi hắn định rời đi, Quy Nhất Tông ép hắn để lại Hồn Khải và dùng bàn tay sương đen chụp xuống, buộc Vương Lâm kích hoạt Thiên Ngưu ấn ký mặc Hồn Khải, tạm tăng tới Không Kiếp sơ kỳ rồi dùng Dịch Linh Ấn chống đỡ nhưng vẫn bị đánh bay thổ huyết. Ngay sau đó Hồn Lệnh được phát, tuyên bố Vương Lâm phản bội Thiên Ngưu Châu và treo thưởng bằng Ngũ Hành Khải hỏa hệ, Quỷ Phàm phó kỳ cùng một viên Thiên Ngưu Châu. Biên Vân và Đường Giai bị trọng thưởng kích động nên mặc Hồn Khải truy kích, trong khi Vân Dật Phong không đuổi theo mà truyền thần niệm cho Đường Giai rồi quỳ trước đại điện chất vấn Tông chủ vì đã biết quan hệ của Vương Lâm với Huyền La Đại Thiên Tôn. Chương cũng hé lộ Thiên Ngưu Châu là chí bảo chỉ có bảy hạt, có thể duy trì Thiên Ngưu Hồn để Hồn Khải dùng được ở xa Thiên Ngưu Châu, còn Quỷ Phàm phó kỳ có thể thi triển uy lực đại trận hộ sơn từ xa. Cuối chương, Vương Lâm lao khỏi Quy Nhất Tông trong cảnh giác nhưng phát hiện toàn tông yên lặng bất thường, không ai ngăn cản và đại trận sơn môn dường như đã đóng lại."},{"chuong":1789,"tieuDe":"Thiên Ngưu Đỉnh Dương","tomTat":"Vương Lâm cảm thấy sự yên tĩnh trong Quy Nhất Tông quá bất thường nhưng không kịp suy nghĩ, lập tức lao khỏi sơn môn; Biên Vân dùng tu vi Không Kiếp hậu kỳ đuổi sát phía sau. Biên Vân mặc kệ điểm đáng ngờ trong thái độ Quy Nhất Tông, lấy Hồn Lệnh của tông chủ làm cớ truy sát Vương Lâm để đổi tặng phẩm, rồi thi triển Thất Tinh sát gọi bảy thiên thạch rơi xuống. Đường Giai bất ngờ đuổi tới, giả vờ muốn giúp Biên Vân để chia Ngũ Hành Hỏa Khải nhưng khi áp sát lại dùng Bát môn phong khóa hắn. Vương Lâm nhận ra khí tức Đường Giai giống Đường San nên bỏ ý định chạy trốn, quay lại phản kích bằng Thất Thải Thương, lục chỉ ma thủ và Tàn Dạ Thuật. Biên Vân phá phong bằng máu và u hồn, dùng tiểu thuẫn trắng chống đỡ nhưng vẫn bị Vương Lâm cùng Đường Giai liên thủ đánh trọng thương. Khi nhận ra Tàn Dạ có dấu vết Tín thuật và rơi vào nguy cơ, Biên Vân gọi hư ảnh Thiên Ngưu bên ngoài thân thể lao vào vầng mặt trời của Tàn Dạ."},{"chuong":1790,"tieuDe":"Câu Nói Kia!","tomTat":"Thiên Ngưu Hồn do Hồn Khải của Biên Vân hóa thành lao vào vầng mặt trời của Tàn Dạ, đánh sụp thần thông của Vương Lâm khiến hắn thổ huyết, còn Biên Vân cũng suy kiệt và rơi tu vi tăng cường. Vương Lâm bất chấp thương thế truy sát Biên Vân, trong khi Đường Giai không tiếp tục giúp đỡ và rời khỏi chiến trường. Khi Biên Vân lâm nguy, một bàn tay đen khổng lồ từ Quy Nhất Tông vươn ra kéo hắn về, buộc Vương Lâm bỏ truy sát và na di rời đi. Vương Lâm vô tình hiện thân tại vùng núi Thất Đạo Tông cũ, vào sơn môn hoang phế, thả Dĩ Ti hộ pháp và chữa thương ba ngày. Trong đại điện cũ, hắn nhớ tới động phủ giới và người xưa, rồi dùng Hồn Diễn Đạo suy tính câu nói Thanh Ngưu lão tổ để lại qua thần thức trên sợi tóc. Từ các chữ cuối, hắn giải ra lời cảnh báo Thiên Ngưu Châu có biến, suy đoán Đại Hồn Môn và Quy Nhất Tông cố ý dùng ban thưởng bất công để ép hắn rời khỏi nơi này. Hắn quyết định rời Thiên Ngưu Châu và cho rằng Lục Ma Châu có thể là nguồn ngăn trở trên đường đi. Đúng lúc đó, Đỗ Thanh đến Thất Đạo Tông theo lệnh Thanh Ngưu lão tổ, giao cho hắn viên đá màu đen tầm thường nhưng ẩn chứa khí tức Hồn Diễn Đạo."},{"chuong":1791,"tieuDe":"Bồi Thường, Ban Thưởng","tomTat":"Vương Lâm nhận hòn đá màu đen từ Đỗ Thanh, không nói rõ lai lịch rồi cáo biệt rời Thất Đạo Tông, còn Đỗ Thanh quay về Đại Hồn Môn để báo Thanh Ngưu lão tổ rằng nhiệm vụ đã hoàn thành. Trong một vùng sa mạc trên Thiên Ngưu Châu, Vương Lâm dùng Hồn Diễn Đạo mở hòn đá, khiến vật này vỡ ra và hiện bốn quầng sáng. Bốn món bên trong lần lượt là áo giáp hình người thổ hệ của Quy Nhất Tông, Quỷ Phàm phó kỳ của hộ sơn đại trận Đại Hồn Môn, Thiên Ngưu Châu mang khí tức Thiên Ngưu và mai rùa chứa bản đồ toàn bộ Đông Châu cùng lời hẹn ba trăm năm của Thanh Ngưu lão tổ. Vương Lâm hiểu ân tình này rất nặng, vái về phía Đại Hồn Môn và hứa sẽ quay lại. Dựa vào bản đồ, hắn định tới Đông Lâm Tông ở Đại Thánh Châu nhưng nhận ra đường chính xa và có thể bị chặn, nên quyết định đi qua Lục Ma Châu vì nơi nguy hiểm nhất có thể lại là nơi an toàn nhất. Trên đường hướng tới Đan Hải, hắn dùng Súc địa thành thốn xen kẽ ẩn nấp bế quan để tránh phải giết tu sĩ Thiên Ngưu Châu. Sau mấy tháng, thương thế của hắn chuyển biến tốt toàn bộ, hắn vượt Cực Thiên thảo nguyên và trong tuyết lớn gần Đan Hải lần đầu muốn bước vào một tòa thành phàm nhân trên Tiên Cương đại lục."},{"chuong":1792,"tieuDe":"Ngăn Trở","tomTat":"Trong tuyết rơi cuối đông, Vương Lâm đi vào một thành trì phàm nhân, nhìn ánh đèn vạn nhà và cảm nhận rõ mình không còn dung nhập được vào phàm trần. Hắn hiểu ba lần hóa phàm đã tới giới hạn, sau đó là đoạn phàm, đồng thời xác nhận mình đã có tám đạo bản nguyên, chỉ còn thiếu một đạo để bước vào Không Kiếp. Mấy tháng sau, hắn vượt qua Đan Hải đã sụp đổ rồi tiến vào Lục Ma Châu, nơi tràn ngập khí tức âm u, lãnh khốc và ma khí. Nhận ra lực lượng ma khí khổng lồ sâu trong châu là Lục Ma Hạt Miếu theo bản đồ mai rùa, hắn không tới gần mà đi vòng về phía biên giới Mạnh Thổ Châu. Tại dãy núi biên giới, Vương Lâm phát hiện hai Lục Ma sứ giả và kiếm khí quen thuộc của Vân Không đang chặn đường. Khi hắn mặc Thiên Ngưu Hồn Khải lao tới, hai sứ giả Không Kiếp trung kỳ không giao chiến mà lần lượt tự bạo, khiến tình thế trở nên cực kỳ quỷ dị. Vương Lâm lấy áo giáp hình người tạo thổ giáp, bộc phát toàn bộ tu vi và Đạo Cổ lực thành hư ảnh khổng lồ để chống đỡ; hư ảnh bị hai đợt tự bạo đánh sụp, dư lực tiếp tục rơi lên lớp giáp của hắn."},{"chuong":1793,"tieuDe":"Lời Thề!","tomTat":"Vương Lâm bị nhiều tầng lực lượng hủy diệt và phong tỏa kéo chậm khi cố rời Lục Ma Châu, trong lúc súc địa thành thốn bị phong ấn và Thiên Ngưu Hồn Khải bắt đầu tổn hại nặng. Vân Không lộ diện trên đỉnh núi cao nhất, dùng kiếm khí liên hoàn, máu vàng hóa chín kiếm ảnh và thanh kiếm cổ kính mang dấu vết Đại Thiên Tôn để ngăn hắn. Vương Lâm gọi kim ấn đối kháng, đánh nát thanh kiếm của Vân Không nhưng kim ấn cũng nứt sâu, rồi dùng Huyết Kiếm xuyên mi tâm giết Vân Không sau khi đối thủ thừa nhận mục tiêu trì hoãn đã đạt. Trên đường tiếp tục lao đi, Vương Lâm nhớ lại ghi chép về Mạnh Thổ Châu, vùng sa mạc hình thành từ truyền thuyết tu sĩ thiên ngoại họ Mạnh bị Tiên Tổ phong ấn. Khi hắn chỉ còn cách Mạnh Thổ Châu chưa tới ngàn dặm, bảy Truyền Tống Trận của Đạo Ma Tông mở ra, đưa hơn trăm tu sĩ tới chặn đường với cái giá cực lớn. Đạo Ma Tông ném ra hàng trăm đầu lâu của tu sĩ Cực Thiên thảo nguyên từng chiến đấu cùng Vương Lâm, gọi đó là đại lễ dành cho hắn. Trước cảnh ấy, Vương Lâm phẫn nộ lập lời thề nếu rời khỏi nơi này thì ngày sau nhất định giết sạch toàn tông Đạo Ma Tông."}];
